-- === 202601013646_init.sql ===
CREATE SCHEMA IF NOT EXISTS bodyfuel;

CREATE TABLE IF NOT EXISTS bodyfuel.user_info (
    id UUID PRIMARY KEY,
    username TEXT NOT NULL UNIQUE,
    name TEXT,
    surname TEXT,
    password TEXT NOT NULL,
    email TEXT UNIQUE,
    phone TEXT,
    email_verified_at TIMESTAMPTZ NULL,
    phone_verified_at TIMESTAMPTZ NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_user_info ON bodyfuel.user_info(username);

-- === 202602021232_add_user_params.sql ===
CREATE SCHEMA IF NOT EXISTS bodyfuel;

DO
$$
    BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'want'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
            CREATE TYPE bodyfuel.want AS ENUM (
                'lose_weight',
                'build_muscle',
                'stay_fit'
                );
        END IF;
    END
$$;

DO
$$
    BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'lifestyle'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
            CREATE TYPE bodyfuel.lifestyle AS ENUM (
                'not_active',
                'active',
                'sportive'
                );
        END IF;
    END
$$;

-- 3. Создаём таблицу user_params
CREATE TABLE IF NOT EXISTS bodyfuel.user_params (
                                                    id UUID PRIMARY KEY,
                                                    id_user UUID NOT NULL REFERENCES bodyfuel.user_info(id) ON DELETE CASCADE,
                                                    height INT,
                                                    photo TEXT,
                                                    wants bodyfuel.want,
                                                    lifestyle bodyfuel.lifestyle
);

-- 4. Создаём индекс, если его нет
CREATE INDEX IF NOT EXISTS idx_user_info_username ON bodyfuel.user_info(username);

-- === 202603021233_add_user_weight.sql ===
CREATE TABLE IF NOT EXISTS bodyfuel.user_weight (
                                                    id UUID PRIMARY KEY,
                                                    id_user UUID NOT NULL REFERENCES bodyfuel.user_info(id) ON DELETE CASCADE,
                                                    weight FLOAT,
                                                    date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_user_info_username ON bodyfuel.user_info(username);

-- === 202604021333_add_new_fields_user_param.sql ===
ALTER TABLE bodyfuel.user_params
    ADD COLUMN IF NOT EXISTS target_workouts_weeks INT,
    ADD COLUMN IF NOT EXISTS target_calories_daily INT,
    ADD COLUMN IF NOT EXISTS target_weight FLOAT;

-- === 202605021333_add_exercise.sql ===
CREATE SCHEMA IF NOT EXISTS bodyfuel;

DO
$$
    BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'level_preparation'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
            CREATE TYPE bodyfuel.level_preparation AS ENUM (
                'beginner',
                'medium',
                'sportsman'
                );
        END IF;
    END
$$;

DO
$$
    BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'exercise_type'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
            CREATE TYPE bodyfuel.exercise_type AS ENUM (
                'cardio',
                'upper_body',
                'lower_body',
                'full_body',
                'flexibility'
                );
        END IF;
    END
$$;

DO
$$
    BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'place_exercise'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
            CREATE TYPE bodyfuel.place_exercise AS ENUM (
                'home',
                'gym',
                'street'
                );
        END IF;
    END
$$;

CREATE TABLE IF NOT EXISTS bodyfuel.exercise (
                                                 id UUID PRIMARY KEY,
                                                 level_preparation bodyfuel.level_preparation NOT NULL,
                                                 name VARCHAR(100) NOT NULL,
                                                 type_exercise bodyfuel.exercise_type NOT NULL,
                                                 description TEXT,
                                                 base_count_reps INT NOT NULL,
                                                 steps INT NOT NULL,
                                                 link_gif TEXT,
                                                 place_exercise bodyfuel.place_exercise NOT NULL,
                                                 avg_calories_per DECIMAL(5,2) NOT NULL,
                                                 base_relax_time INT NOT NULL
                                             );

CREATE INDEX IF NOT EXISTS idx_exercise_level ON bodyfuel.exercise(level_preparation);
CREATE INDEX IF NOT EXISTS idx_exercise_type ON bodyfuel.exercise(type_exercise);
CREATE INDEX IF NOT EXISTS idx_exercise_place ON bodyfuel.exercise(place_exercise);
CREATE INDEX IF NOT EXISTS idx_exercise_name ON bodyfuel.exercise(name);

-- === 202606031434_add_workouts.sql ===
CREATE SCHEMA IF NOT EXISTS bodyfuel;

DO
$$
BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'workouts_level'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
CREATE TYPE bodyfuel.workouts_level AS ENUM (
                'workout_light',
                'workout_middle',
                'workout_hard'
                );
END IF;
END
$$;

DO
$$
BEGIN
        IF NOT EXISTS (SELECT 1
                       FROM pg_type
                       WHERE typname = 'workouts_status'
                         AND typnamespace = 'bodyfuel'::regnamespace) THEN
CREATE TYPE bodyfuel.workouts_status AS ENUM (
                'workout_created',
                'workout_done',
                'workout_in_active',
                'workout_failed'
                );
END IF;
END
$$;

CREATE TABLE IF NOT EXISTS bodyfuel.workout (
    id UUID PRIMARY KEY,
    user_id UUID NOT NULL,
    level bodyfuel.workouts_level NOT NULL,
    status bodyfuel.workouts_status NOT NULL,
    total_calories INT NOT NULL,
    prediction_calories INT NOT NULL,
    duration INT NOT NULL,
    created_at TIMESTAMP NOT NULL,
    updated_at TIMESTAMP NOT NULL
    );

CREATE INDEX IF NOT EXISTS idx_workout_user_id ON bodyfuel.workout(user_id);
CREATE INDEX IF NOT EXISTS idx_workout_status ON bodyfuel.workout(status);
CREATE INDEX IF NOT EXISTS idx_workout_level ON bodyfuel.workout(level);
CREATE INDEX IF NOT EXISTS idx_workout_created_at ON bodyfuel.workout(created_at);
CREATE INDEX IF NOT EXISTS idx_workout_user_status ON bodyfuel.workout(user_id, status);

-- === 20260706031424_add_workout_exercise.sql ===
CREATE SCHEMA IF NOT EXISTS bodyfuel;

-- Создаем enum для статуса выполнения упражнения
CREATE TYPE bodyfuel.exercise_status AS ENUM ('pending', 'in_progress', 'completed', 'skipped');

-- Создаем таблицу для связи тренировок и упражнений
CREATE TABLE IF NOT EXISTS bodyfuel.workouts_exercise (
                                                          workout_id UUID NOT NULL,
                                                          exercise_id UUID NOT NULL,
                                                          modify_reps INT NOT NULL,
                                                          modify_relax_time INT NOT NULL,
                                                          calories INT NOT NULL,
                                                          sets INT NOT NULL DEFAULT 1,
                                                          status bodyfuel.exercise_status NOT NULL DEFAULT 'pending',
                                                          created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
                                                          updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
    );

-- Создаем индексы для оптимизации запросов
CREATE INDEX idx_workouts_exercise_workout_id
    ON bodyfuel.workouts_exercise(workout_id);

CREATE INDEX idx_workouts_exercise_exercise_id
    ON bodyfuel.workouts_exercise(exercise_id);

CREATE INDEX idx_workouts_exercise_status
    ON bodyfuel.workouts_exercise(status);

CREATE INDEX idx_workouts_exercise_updated_at
    ON bodyfuel.workouts_exercise(updated_at);

-- Составной индекс для частых фильтров
CREATE INDEX idx_workouts_exercise_workout_status
    ON bodyfuel.workouts_exercise(workout_id, status);

-- === 20260806031424_fill_exercises.sql ===
-- ==================== УПРАЖНЕНИЯ ДЛЯ НАЧИНАЮЩИХ (beginner) ====================

-- Upper Body для начинающих (home)
-- ==================== УПРАЖНЕНИЯ ДЛЯ НАЧИНАЮЩИХ (beginner) ====================

-- Upper Body для начинающих (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отжимания от стены', 'upper_body', 'Отжимания от стены — базовое упражнение с собственным весом, обеспечивающее минимальную нагрузку на суставы и возможность точно регулировать интенсивность за счёт расстояния до стены.

Встаньте лицом к стене на расстоянии вытянутой руки. Ладони поставьте на стену на ширине плеч или чуть шире, пальцы смотрят вверх. Ноги на ширине таза, корпус прямой от пяток до макушки. Напрягите живот и ягодицы, чтобы поясница не прогибалась.

На вдохе медленно согните руки в локтях, приближая грудь к стене. Локти двигаются вдоль корпуса под углом примерно 45 градусов, не разводите их в стороны. Следите, чтобы голова не уходила вперёд, а взгляд оставался прямо на стену. Остановитесь, когда нос окажется в 5–10 см от стены — это нижняя точка.

На выдохе мощно выпрямите руки, возвращаясь в исходное положение. В верхней точке не блокируйте локти полностью, оставьте микросгиб. Дыхание: вниз — вдох, вверх — выдох. Темп медленный и контролируемый: спуск 2 секунды, подъём 1 секунду.

Основные ошибки: провисшая поясница, поднятые плечи к ушам, слишком маленькая амплитуда (менее 10 см сгибания рук), задержка дыхания на усилии. Для увеличения сложности отодвиньтесь от стены дальше — чем дальше ноги, тем больше веса тела приходится на руки. Для облегчения подойдите ближе. Перед выполнением рекомендуется сделать разминку запястий.', 12, 4, '/exercises/wall-pushup.gif', 'home', 0.56, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Подъемы рук с бутылками', 'upper_body', 'Подъемы рук с бутылками — изолированное упражнение для развития дельтовидных мышц (плеч). В качестве отягощения используются пластиковые бутылки с водой или песком. Упражнение укрепляет средние и передние пучки дельт, улучшает форму плеч и осанку.

Возьмите в каждую руку по бутылке одинакового объёма. Встаньте прямо, ноги на ширине плеч, колени слегка мягкие. Руки опущены вдоль туловища, локти чуть согнуты, чтобы не перегружать суставы. Корпус зафиксирован: пресс напряжён, поясница не прогибается, взгляд прямо.

На выдохе медленно поднимите руки в стороны до уровня плеч или чуть ниже (кисти, локти и плечи образуют одну линию). Не рывком, а за счёт усилия дельт. Представьте, что вы наливаете воду из бутылки — мизинец должен быть выше большого пальца в верхней точке. Задержитесь на 1 секунду, чувствуя напряжение в плечах.

На вдохе так же медленно опустите руки в исходное положение, сохраняя контроль. Не бросайте вес, даже внизу мышцы должны быть в тонусе. Дыхание: усилие (подъём) на выдохе, опускание на вдохе.

Главные ошибки: раскачка корпусом (инерция), подъём рук выше плеч (травмоопасно для сустава), сгибание локтей слишком сильно (превращается в тягу), запрокидывание головы назад. Для облегчения возьмите бутылки меньшего объёма или поднимайте руки только до 45 градусов. Для усложнения увеличивайте объём воды или задерживайтесь в верхней точке дольше.', 15, 4, '/exercises/lateral-raise.gif', 'home', 0.31, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Разгибание рук из-за головы', 'upper_body', 'Разгибание рук из-за головы — изолированное упражнение для тренировки трицепса (задней поверхности плеча). Выполняется с гантелью, бутылкой воды или эспандером. Упражнение эффективно прорабатывает длинный пучок трицепса, отвечающий за объём и силу рук.

Сядьте на устойчивый стул или край дивана с прямой спиной. Возьмите одну бутылку (или гантель) двумя руками за верхнюю часть — ладони под дном, большие пальцы обхватывают горлышко. Поднимите руки вверх и заведите бутылку за голову так, чтобы локти смотрели строго в потолок, а предплечья были направлены вниз. Прижмите локти ближе к ушам, не разводите их в стороны. Спина прямая, пресс напряжён, поясница чуть прогнута естественно.

На вдохе зафиксируйте плечи и начните сгибать локти, опуская бутылку за голову. Движение только в локтевом суставе — плечи остаются неподвижными. Остановитесь, когда угол в локте достигнет примерно 90 градусов или когда почувствуете комфортное растяжение в трицепсе. Не опускайте бутылку слишком низко — это перегружает локтевой сустав.

На выдохе мощным и плавным движением выпрямите руки, возвращая бутылку в исходное положение. В верхней точке не блокируйте локти полностью, оставьте микросгиб. Темп: 2 секунды на опускание, 1 секунда на подъём. Дыхание: вниз — вдох, вверх — выдох.

Основные ошибки: раскачивание корпусом (помогаете спиной), разведение локтей в стороны (нагрузка уходит в плечи), слишком быстрый подъём (работает инерция), сгибание запястий. Если сложно удерживать бутылку двумя руками — используйте одну руку, а вторую поставьте на бедро для опоры. Для облегчения возьмите меньший вес или уменьшите амплитуду. Для усложнения увеличьте вес либо добавьте паузу в нижней точке.', 12, 4, '/exercises/overhead-extension.gif', 'home', 0.45, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Сгибание рук с бутылками', 'upper_body', 'Сгибание рук с бутылками — базовое упражнение для тренировки бицепса в домашних условиях. В качестве отягощения используются пластиковые бутылки с водой или песком. Упражнение формирует рельеф передней поверхности плеча, увеличивает силу рук.

Встаньте прямо, ноги на ширине плеч, колени слегка мягкие, чтобы не блокировать суставы. Возьмите в каждую руку по бутылке одинакового объёма. Руки опущены вдоль туловища, ладони смотрят вперёд (супинированный хват). Локти прижаты к корпусу и остаются неподвижными на протяжении всего движения. Плечи расправлены, лопатки сведены, пресс и ягодицы напряжены для стабилизации поясницы.

На выдохе, сохраняя локти прижатыми к рёбрам, начните сгибать руки в локтях, поднимая бутылки к плечам. Движение выполняется только за счёт сокращения бицепса, без раскачки корпуса. В верхней точке бутылки должны почти коснуться плеч, а угол в локте стать острым (менее 90 градусов). Задержитесь на 1 секунду и дополнительно напрягите бицепс — это пиковое сокращение.

На вдохе плавно и подконтрольно разогните руки, возвращая бутылки в исходное положение. Не бросайте вес, даже в нижней точке бицепс должен оставаться в лёгком напряжении (не выключайте суставы полностью). Темп: 1–2 секунды на подъём, 2 секунды на опускание. Дыхание: усилие (подъём) на выдохе, расслабление (опускание) на вдохе.

Главные ошибки: раскачка корпусом (помогаете спиной и ногами), отрыв локтей от корпуса (нагрузка уходит в передние дельты), сгибание запястий (перегрузка связок), слишком быстрое опускание (теряется эксцентрическая фаза). Если не удаётся держать локти на месте — сядьте на стул и прижмите локти к бёдрам. Для облегчения уменьшите объём бутылок или сократите амплитуду, поднимая руки только до прямого угла. Для усложнения увеличьте вес или добавьте паузу в верхней точке.', 12, 4, '/exercises/bicep-curl.gif', 'home', 0.48, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Махи руками', 'upper_body', 'Махи руками — динамическое упражнение для укрепления плечевого пояса, особенно средней и передней дельтовидной мышцы. Выполняется как с собственным весом (для разминки), так и с небольшими отягощениями — бутылками воды, гантелями или эспандерами. Упражнение улучшает подвижность суставов, формирует округлые плечи и помогает исправить осанку.

Встаньте прямо, ноги на ширине плеч, колени чуть согнуты. Спина прямая, пресс напряжён, лопатки сведены. Руки опущены вдоль туловища, локти слегка согнуты для защиты суставов. Если используете бутылки, возьмите их нейтральным хватом (ладонями друг к другу). Взгляд направлен вперёд, шея расслаблена.

На выдохе поднимите руки в стороны до уровня плеч — кисти, локти и плечи должны оказаться на одной линии. Движение плавное, без рывка, за счёт усилия дельт. В верхней точке ладони смотрят вниз, мизинцы чуть выше больших пальцев (имитация наливания воды). Задержитесь на секунду, чувствуя жжение в середине плеч.

На вдохе медленно и подконтрольно опустите руки вниз, не бросая вес. В нижней точке не касайтесь бёдер — оставьте лёгкое напряжение, чтобы мышцы не отдыхали. Темп: 2 секунды на подъём, 2 секунды на опускание. Корпус остаётся неподвижным — работают только руки.

Основные ошибки: рывки и инерция (раскачка корпусом), подъём рук выше плеч (травмирует сустав), согнутые локти слишком сильно (укорачивает рычаг и снижает нагрузку), округление спины или прогиб в пояснице. Если плечи щёлкают — уменьшите амплитуду или возьмите меньший вес (или делайте без веса). Для облегчения выполняйте махи сидя, прижавшись спиной к стене — это исключит раскачку. Для усложнения увеличьте вес бутылок или задержитесь в верхней точке дольше.', 20, 4, '/exercises/arm-swings.gif', 'home', 0.14, 20);

-- Upper Body для начинающих (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Жим гантелей сидя', 'upper_body', 'Жим гантелей сидя — базовое многосуставное упражнение для развития всех трёх пучков дельтовидных мышц, а также трицепсов и верхней части грудных мышц. Выполняется с гантелями или тяжёлыми бутылками. Сидячее положение снимает нагрузку с поясницы, позволяя сконцентрироваться именно на плечах. Упражнение не требует стойки или страховщика.

Сядьте на жёсткий стул или табурет со спинкой. Прижмитесь поясницей к спинке — это защитит позвоночник от прогиба. Ноги плотно стоят на полу на ширине плеч, колени согнуты под 90 градусов. Возьмите гантели (бутылки) в обе руки, поднимите их до уровня плеч. Локти смотрят в стороны и чуть вперёд, предплечья вертикальны, кисти развёрнуты ладонями от себя. Плечи опущены (не поднимайте их к ушам), лопатки сведены, пресс напряжён.

На выдохе мощным, но плавным движением выжмите гантели вертикально вверх, почти полностью выпрямляя руки. Траектория должна быть слегка дугообразной — к середине над головой, а не строго по бокам. В верхней точке гантели могут коснуться друг друга, но не блокируйте локти полностью, оставьте микросгиб. Задержитесь на 0.5 секунды.

На вдохе медленно и контролируемо опустите гантели обратно до уровня плеч (или чуть ниже, до параллели предплечий с полом). Не бросайте вес. Сохраняйте напряжение в плечах даже в нижней точке. Локти не должны опускаться ниже плечевых суставов, чтобы не травмировать капсулу сустава. Темп: 1–2 секунды на подъём, 2–3 секунды на опускание.

Главные ошибки: отрыв поясницы от спинки (прогиб), выталкивание ногами (помощь), слишком широкая или узкая траектория, разворот локтей назад (нагрузка уходит в трицепс), сгибание запястий назад. Если сложно держать равновесие — выполняйте стоя, но с контролем прогиба. Для облегчения возьмите меньший вес либо уменьшите амплитуду, опуская руки не до плеч, а до угла 45 градусов. Для усложнения выполняйте жим поочерёдно (одна рука вверху, другая внизу) или добавьте поворот гантелей в верхней точке.', 12, 4, '/exercises/seated-dumbbell-press.gif', 'gym', 0.69, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Тяга верхнего блока', 'upper_body', 'Тяга верхнего блока — базовое многосуставное упражнение для развития широчайших мышц спины. Выполняется на специализированном блочном тренажере. Имитирует подтягивания на турнике, но в более контролируемой и безопасной форме, позволяя эффективно прорабатывать спину даже тем, кто пока не может подтягиваться самостоятельно. Упражнение помогает сформировать V-образный силуэт, улучшить осанку и увеличить силу тяговых мышц.

Сядьте на скамью тренажера, плотно зафиксируйте колени под поддерживающими валиками и упритесь ступнями в пол. Угол в коленях должен составлять примерно 90 градусов — это обеспечит устойчивое положение и предотвратит подъем корпуса вверх. Возьмитесь за рукоять прямым (пронированным) хватом на ширине чуть шире плеч. Ладони смотрят от себя. Слегка отклоните корпус назад на 20–30 градусов, сохраняя естественные изгибы позвоночника. Грудная клетка приподнята, лопатки сведены и опущены, плечи расслаблены и не подняты к ушам. Пресс и мышцы кора напряжены для стабилизации корпуса.

На выдохе мощным и плавным движением начните тянуть рукоять вниз и назад за счёт сведения лопаток. Ведущая мысль — опускайте не гриф к груди, а тяните локти вниз и назад к бокам. Локти движутся строго по бокам корпуса, не уходят вперёд и не разворачиваются в стороны. Гриф должен коснуться верхней части грудной клетки (ключиц или чуть ниже подбородка). В нижней точке сделайте паузу на 1 секунду, дополнительно напрягая широчайшие мышцы и сводя лопатки.

На вдохе медленно и подконтрольно верните рукоять в исходное положение, полностью выпрямляя руки и позволяя широчайшим мышцам растянуться в верхней точке. Не бросайте вес — эксцентрическая фаза (подъём грифа) должна быть медленнее концентрической (тяги вниз). Рекомендуемый темп: 2 секунды (тяга вниз), пауза 1 секунда, 3 секунды (возврат вверх). Дыхание: усилие (тяга) на выдохе, возврат на вдохе.

Главные ошибки: раскачка корпуса (читинг) и использование инерции вместо силы мышц — это перекладывает нагрузку с широчайших на бицепсы и поясницу. Отсутствие паузы в нижней точке и сведение лопаток снижает эффективность. Опускание грифа слишком низко (на живот) или за голову перегружает плечевые суставы. Слишком узкий хват уменьшает акцент на широчайших. Округлённая спина или прогиб в пояснице (мост) опасны для позвоночника.

Существует несколько вариантов хвата: широкий хват (руки значительно шире плеч) — максимально нагружает внешнюю часть широчайших; узкий хват (ладони вместе или на ширине плеч) — акцент на средней части спины и бицепсах; обратный хват (ладони к себе) — сильнее нагружает бицепс и нижнюю часть широчайших; нейтральный параллельный хват (ладони друг к другу) — наиболее естественное положение для запястий. Вариант выполнения за голову опускает гриф на заднюю поверхность шеи, но требует большой подвижности плеч и считается более травмоопасным. Для коррекции мышечного дисбаланса можно выполнять упражнение поочерёдно каждой рукой с D-образной рукоятью.', 12, 4, '/exercises/lat-pulldown.gif', 'gym', 0.66, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Разведение гантелей лежа', 'upper_body', 'Разведение гантелей лёжа — изолированное упражнение для глубокой проработки грудных мышц, преимущественно их внутренней и внешней частей. В отличие от жима гантелей, здесь нет работы трицепсов и передних дельт — нагрузка концентрируется именно на груди. Выполняется на горизонтальной скамье или на полу (упрощённый вариант).

Лягте на скамью, плотно прижавшись к ней спиной и ягодицами. Ноги устойчиво стоят на полу на ширине плеч, колени согнуты под прямым углом. Возьмите в каждую руку по гантели. Начните с гантелей в вытянутых руках над грудью, ладони смотрят друг на друга (нейтральный хват). Локти слегка согнуты, запястья зафиксированы. Лопатки сведены, поясница сохраняет естественный лёгкий прогиб, но не отрывается от скамьи. Голова лежит на скамье, взгляд вверх.

На вдохе медленно разведите руки в стороны по широкой дуге, сохраняя локти чуть согнутыми (фиксированный угол на протяжении всего движения). Опускайте гантели до комфортного растяжения в грудных мышцах — обычно когда руки оказываются на уровне грудной клетки или чуть ниже, а гантели находятся на одной линии с плечами. Не опускайте локти слишком низко, чтобы не травмировать плечевые суставы. В нижней точке задержитесь на 0.5–1 секунду, ощущая растяжение груди.

На выдохе мощным, но плавным движением сведите гантели обратно над грудью, как будто обнимаете большой мяч. В верхней точке не стучите гантелями и не выпрямляйте локти полностью — оставьте микросгиб. Концентрируйтесь на сведении грудных мышц. Темп: 2–3 секунды на разведение (вниз), 1–2 секунды на сведение (вверх). Дыхание: вниз — вдох, вверх — выдох.

Главные ошибки: разгибание локтей (превращает упражнение в жим), слишком тяжёлый вес (рывки и потеря контроля), округление плеч вперёд в верхней точке (выключает грудь), отрыв поясницы от скамьи (перегружает позвоночник). При боли в плечах уменьшите амплитуду или возьмите меньший вес. Новичкам лучше начинать на полу, лёжа на коврике — скамья ограничит амплитуду и снизит риск травмы.

Вариации: разведение гантелей под углом 30 градусов (головой вверх) акцентирует нагрузку на верхнюю часть груди; сведение через блоки в кроссовере даёт постоянное напряжение; разведение поочерёдно или с поворотом кистей в верхней точке (ладонями к себе) для дополнительной стимуляции.', 12, 4, '/exercises/dumbbell-fly.gif', 'gym', 0.59, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Тяга гантели в наклоне', 'upper_body', 'Тяга гантели в наклоне — базовое одностороннее упражнение для развития широчайших мышц спины, нижней части трапеций и ромбовидных мышц. Выполняется с одной гантелью (или тяжёлой бутылкой) и позволяет прорабатывать каждую половину спины изолированно, помогая исправить мышечный дисбаланс.

Встаньте сбоку от устойчивой опоры — скамьи, стула или стены. Поставьте на опору одно колено и одноимённую руку (например, левое колено и левую руку). Вторая нога стоит на полу чуть сзади и в сторону для устойчивости. Свободной рукой возьмите гантель нейтральным хватом (ладонь внутрь, к корпусу). Спина прямая от ягодиц до макушки, пресс напряжён. Взгляд направлен в пол чуть впереди опорной руки, шея — продолжение позвоночника. Грудная клетка приподнята, лопатка на рабочей стороне опущена и сведена к позвоночнику.

На выдохе мощным движением подтяните гантель вверх, сгибая руку в локте. Локоть движется строго вдоль туловища, не уходя в сторону. Траектория — от пола к поясу или чуть выше (до уровня талии). В верхней точке гантель должна оказаться у нижних рёбер или ближе к пояснице. Сделайте паузу на 1 секунду, дополнительно сжимая лопатки и напрягая широчайшую мышцу. Локоть при этом поднимается выше корпуса — это нормально, главное не разворачивать его наружу.

На вдохе медленно и подконтрольно опустите гантель вниз до полного выпрямления руки, позволяя широчайшей мышце растянуться. Не бросайте вес. В нижней точке плечо опущено, а лопатка расслаблена и вытянута вперёд для максимальной амплитуды. Темп: 1–2 секунды на подъём, пауза 1 секунда, 2–3 секунды на опускание.

Главные ошибки: округление спины (особенно в пояснице) — травмоопасно; подъём плеча к уху (включает верхнюю трапецию вместо широчайших); разворот локтя в сторону (нагрузка уходит в дельту и трицепс); рывки и использование инерции корпусом; поворот корпуса в сторону подъёма (читинг). При напряжении в пояснице возьмите меньший вес или уменьшите наклон корпуса (разместите опору выше). При болях в шее контролируйте взгляд: не задирайте голову вверх.

Вариации: хват ладонью от себя (пронированный) сильнее нагружает нижнюю часть широчайших и бицепс; хват ладонью к себе (супинированный) — акцент на бицепс и среднюю часть спины. Можно выполнять без опоры, обеими ногами на полу, с наклоном корпуса до параллели с полом — это сложнее и требует сильного кора. Для облегчения допустимо опираться ладонью одной руки о стену, а не лежать на скамье.', 12, 4, '/exercises/dumbbell-row.gif', 'gym', 0.63, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Жим штанги лежа', 'upper_body', 'Жим штанги лежа — базовое многосуставное упражнение для развития грудных мышц, передних пучков дельт и трицепсов. Считается одним из трёх основных в силовом тренинге. Выполняется на горизонтальной скамье со штангой (или с гантелями). Упражнение эффективно увеличивает массу и силу верха тела, укрепляет плечевой пояс.

Лягте на скамью так, чтобы гриф находился на уровне глаз. Лопатки плотно сведены и прижаты к скамье, грудная клетка приподнята, поясница сохраняет естественный лёгкий прогиб (не отрывайте таз от скамьи). Ноги устойчиво стоят всей стопой на полу, чуть шире плеч. Возьмитесь за гриф закрытым хватом (большой палец вокруг грифа) чуть шире плеч — классическая ширина, при которой в нижней точке предплечья вертикальны, а угол в локтях составляет около 75–90 градусов. Снимите штангу со стоек на выдохе, зафиксируйте её над грудью на прямых руках.

На вдохе медленно опустите штангу к нижней части груди (примерно на уровень сосков). Локти движутся под углом примерно 45–60 градусов к корпусу, не разводите их в стороны перпендикулярно телу — это травмирует плечи. Гриф должен коснуться груди лёгким касанием, без отбива. В нижней точке сделайте паузу на 0.5 секунды, сохраняя напряжение в груди.

На выдохе мощным плавным движением выжмите штангу вверх, немного назад — в исходное положение над плечевыми суставами. Не блокируйте локти полностью в верхней точке, оставьте микросгиб. Темп: 2–3 секунды на опускание, 1–2 секунды на подъём. Дыхание: опускание — вдох, подъём — выдох. Взгляд направлен в точку на потолке или на гриф.

Главные ошибки: отрыв таза от скамьи («мост» — снижает амплитуду и нагружает поясницу); слишком широкая постановка рук (нагрузка на плечи и грудину); опускание грифа на шею или живот; выключение локтей в верхней точке (удар по суставам); разведение локтей в стороны (риск травмы вращательной манжеты); отбив грифа от груди (опасно для рёбер). При боли в плечах уменьшите ширину хвата или опускайте гриф чуть выше (на верх груди).

Вариации: жим узким хватом — акцент на трицепс и внутреннюю часть груди; жим с паузой (касание груди и остановка) — развивает взрывную силу; жим в тренажёре Смита — более безопасный вариант; жим на наклонной скамье (30–45 градусов) — прорабатывает верх груди. При отсутствии штанги можно использовать две гантели — это сложнее в стабилизации, но безопаснее для плеч.', 10, 4, '/exercises/barbell-bench-press.gif', 'gym', 1.2, 60);

-- Upper Body для начинающих (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отжимания от скамьи', 'upper_body', 'Отжимания от скамьи обратным хватом (обратные отжимания, трицепсовые отжимания) — эффективное упражнение для проработки трицепсов, передних пучков дельт и верхней части грудных мышц. Выполняется с использованием любой устойчивой возвышенности: скамьи, стула, тумбы или низкого турника. Нагрузка регулируется высотой опоры: чем ниже скамья, тем тяжелее.

Повернитесь спиной к скамье. Сядьте на её край, ладони поставьте на край скамьи на ширине плеч, пальцы смотрят вперёд (обхватывают край). Ноги вытяните вперёд, пятки упираются в пол. Таз находится прямо перед скамьёй, корпус вертикален. Согните руки в локтях и опустите таз вниз, пока не почувствуете лёгкое растяжение в трицепсах и плечах. Локти при этом движутся строго назад, не разводитесь в стороны. Спина прямая, пресс напряжён, плечи опущены.

На вдохе медленно опускайте таз вниз, продолжая сгибать локти до прямого угла (90 градусов) или чуть глубже, если позволяет подвижность плеч. Не опускайтесь слишком низко — это травмирует плечевые суставы. В нижней точке сделайте паузу 0.5 секунды.

На выдохе мощным движением выжмите себя вверх за счёт трицепсов, полностью выпрямляя руки, но не блокируя локти. В верхней точке таз должен быть на одном уровне с коленями или чуть выше, корпус остаётся прямым. Темп: 2–3 секунды вниз, 1–2 секунды вверх.

Главные ошибки: округление спины (сутулость) — перегружает позвоночник; разведение локтей в стороны — нагрузка уходит в плечи и грудь; опускание таза слишком низко (локти выше плеч) — риск травмы; рывки и помощь ногами. Если сложно — поставьте ноги ближе к скамье (согните колени) или используйте более высокую опору (например, диван). Для усложнения положите на бёдра рюкзак с грузом или выпрямите ноги на другой скамье (таз в воздухе).', 10, 4, '/exercises/bench-dips.gif', 'street', 0.85, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Подтягивания на низкой перекладине', 'upper_body', 'Подтягивания на низкой перекладине (австралийские подтягивания) — горизонтальные подтягивания, при которых ноги остаются на земле. Упражнение эффективно для проработки широчайших мышц спины, ромбовидных и бицепсов. Нагрузка регулируется углом наклона тела: чем тело горизонтальнее, тем тяжелее.

Возьмитесь за перекладину хватом на ширине плеч ладонями от себя (прямой хват) или к себе (обратный хват — легче для бицепса). Повисните, ноги вытяните вперёд и поставьте пятки на пол. Тело прямое от пяток до макушки. Таз не проваливается, пресс напряжён, лопатки сведены. Чем ближе ноги под перекладину, тем вертикальнее тело и легче упражнение. Чем дальше ноги, тем тяжелее.

На выдохе подтяните грудную клетку к перекладине, сгибая руки в локтях и сводя лопатки вместе. Локти движутся вдоль корпуса, не разводитесь. Старайтесь коснуться перекладины верхней частью груди (не подбородком). В верхней точке задержитесь на секунду, максимально напрягая спину.

На вдохе медленно и подконтрольно опуститесь вниз до полного выпрямления рук, позволяя широчайшим мышцам растянуться. Не бросайте вес. Темп: 2 секунды на подъём, пауза 1 секунда, 3 секунды на опускание. Дыхание: подъём — выдох, опускание — вдох.

Главные ошибки: провал таза (живот опускается ниже перекладины) из-за слабости кора; подъём плеч к ушам (вместо сведения лопаток); рывки ногами и раскачка корпуса. Для облегчения поставьте ноги ближе к перекладине (тело почти вертикально). Для усложнения используйте узкий хват или выполняйте с паузой внизу.', 8, 4, '/exercises/australian-pullup.gif', 'street', 1.73, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отжимания от брусьев с поддержкой', 'upper_body', 'Отжимания от брусьев с поддержкой ног — облегчённый вариант классических отжиманий на брусьях. Поддержка ног (постановка на скамью или резиновая петля) снижает вес тела и позволяет освоить правильную технику без риска травмировать плечи.

Встаньте на брусья, упритесь в них прямыми руками, плечи опущены и стабилизированы. Заведите ноги назад и поставьте их на невысокую опору (скамью, степ-платформу) так, чтобы таз был чуть выше уровня рук. Можно также использовать резиновый эспандер, закреплённый на брусьях и под коленями. Корпус держите прямо, без раскачки. Локти на старте почти прямые.

На вдохе медленно сгибайте локти, опуская корпус вниз, пока не почувствуете комфортное растяжение в грудных мышцах и трицепсах. Остановитесь, когда угол в локте достигнет 90 градусов или чуть меньше, но не ниже параллели плеча с брусьями. Голову не наклоняйте, смотрите вперёд.

На выдохе мощным движением выжмите себя вверх, возвращаясь в исходное положение. Не блокируйте локти в верхней точке. Темп: 2 секунды вниз, 1 секунда вверх. По мере роста силы постепенно уменьшайте поддержку: сначала уберите скамью, оставив только эспандер, затем переходите к обычным отжиманиям на брусьях.

Главные ошибки: слишком широкий хват на брусьях (нагрузка на плечи), округление плеч вперёд (сутулость), опускание ниже безопасной точки (боль в ключицах), раскачка корпусом. При боли в плечах уменьшите амплитуду или используйте более высокую опору для ног.', 6, 4, '/exercises/assisted-dips.gif', 'street', 2.5, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Вис на перекладине', 'upper_body', 'Вис на перекладине — статическое упражнение для укрепления хвата, мышц предплечий, кистей и пальцев. Растягивает позвоночник, снимает напряжение с поясницы и подготавливает суставы к более сложным движениям. Для начинающих вис — первый шаг к подтягиваниям.

Возьмитесь за перекладину прямым хватом на ширине плеч (или чуть шире). Повисните на прямых руках, полностью расслабив корпус. Ноги чуть согнуты в коленях или выпрямлены — не касаются пола. Плечи опущены вниз (не подняты к ушам), лопатки расслаблены. Голова нейтрально, взгляд вперёд. Дышите ровно, не задерживайте дыхание.

Задача — провисеть внизу как можно дольше, удерживая вес тела только силой кистей и предплечий. Не раскачивайтесь. Если пальцы соскальзывают — используйте магнезию или перчатки. При слабом хвате допускается вис с частичным весом (поставив одну ногу на опору).

Главные ошибки: подъём плеч к ушам (включает трапеции, утомляет ненужные мышцы), раскачка корпуса, задержка дыхания, попытка подтянуться (это другое упражнение). При болях в запястьях попробуйте хват на перекладине с поворотом кистей (нейтральный, как на рукоятях).', 1, 4, '/exercises/hanging.gif', 'street', 2.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отжимания от турника', 'upper_body', 'Отжимания от турника (отжимания в наклоне с опорой о горизонтальную перекладину) — упражнение для грудных мышц, передних дельт и трицепсов, выполняемое под углом. В отличие от отжиманий от пола, корпус наклонён, а ноги на земле, что делает движение легче. Регулировка нагрузки: чем выше турник, тем легче.

Встаньте лицом к турнику на расстоянии вытянутых рук. Обхватите перекладину прямым хватом на ширине плеч. Ноги выпрямлены, пятки на полу. Тело — прямая линия от пяток до макушки. Пресс напряжён, поясница не прогибается. Чем ближе ноги к турнику, тем вертикальнее тело и легче упражнение.

На вдохе согните руки в локтях, опуская грудь к перекладине. Локти движутся под углом 45 градусов к корпусу, не разводите их в стороны. Остановитесь, когда грудь окажется в 5–10 см от турника. Не касайтесь перекладины головой.

На выдохе мощным движением выпрямите руки, возвращаясь в исходное положение. В верхней точке не блокируйте локти. Темп: 2 секунды вниз, 1 секунда вверх. Дыхание: вниз — вдох, вверх — выдох.

Главные ошибки: прогиб в пояснице (живот «висает»), подъём плеч к ушам, неполная амплитуда (сгибание рук на 5 см), отведение локтей строго в стороны. Для усложнения отодвиньте ноги дальше от турника (тело почти горизонтально) или поставьте одну ногу на вторую (уменьшите опору). Для облегчения подойдите ближе или найдите более высокий турник.', 10, 4, '/exercises/bar-pushup.gif', 'street', 0.75, 45);

-- Lower Body для начинающих (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Приседания со стулом', 'lower_body', 'Приседания со стулом — облегчённый вариант классических приседаний. Стул служит ориентиром глубины и страховкой, предотвращая падение назад. Упражнение укрепляет квадрицепсы, ягодичные мышцы, бицепс бедра и мышцы кора, а также учит правильному паттерну приседания без округления спины.

Поставьте устойчивый стул или табурет позади себя на расстоянии вытянутой руки. Встаньте прямо, ноги на ширине плеч, носки чуть развёрнуты наружу (на 15–30 градусов). Руки вытяните вперёд для баланса или держите на поясе. Спина прямая, лопатки сведены, пресс напряжён, взгляд вперёд.

На вдохе начните приседать, отводя таз назад (как будто хотите закрыть дверь ягодицами). Колени при этом остаются на одной линии со стопами — не заваливаются внутрь и не выходят далеко вперёд за носки. Спину держите прямой, не округляйте поясницу. Опускайтесь до тех пор, пока ягодицы легко коснутся сиденья стула. Не садитесь полностью и не расслабляйтесь — лишь коснитесь и сразу начинайте подъём.

На выдохе мощным движением выпрямите ноги, возвращаясь в исходное положение. В верхней точке не блокируйте колени, оставьте микросгиб. Темп: 2–3 секунды вниз, 1–2 секунды вверх. Всё движение контролируемое, без рывков.

Главные ошибки: округление спины (сутулость) и наклон корпуса вперёд; колени «съезжают» внутрь (вальгус) или выходят за носки; отрыв пяток от пола (недостаточная гибкость голеностопа); касание стула с ударом (резкая нагрузка на позвоночник). Если пятки отрываются — подложите под них небольшой блин или свёрнутое полотенце. Для усложнения уберите стул и выполняйте обычные приседания, либо возьмите в руки бутылки с водой.', 15, 4, '/exercises/chair-squat.gif', 'home', 0.45, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады назад', 'lower_body', 'Выпады назад — одностороннее упражнение для развития ягодичных мышц, квадрицепсов и бицепса бедра. В отличие от выпадов вперёд, этот вариант значительно меньше нагружает коленные суставы, а передняя нога остаётся более стабильной. Упражнение также улучшает координацию и баланс.

Встаньте прямо, ноги на ширине таза, руки на поясе или опущены вдоль туловища. Корпус прямой, пресс напряжён, взгляд вперёд. Сделайте шаг назад правой ногой, приземляясь на носок. Левая нога остаётся на месте, стопа плотно прижата к полу.

На вдохе согните обе ноги в коленях, опуская таз вниз, пока угол в левом (переднем) колене не достигнет 90 градусов, а правое колено почти не коснётся пола (на 2–3 см выше). Левое колено должно находиться прямо над пяткой или чуть позади, не выходить за носок. Корпус держите вертикально, не наклоняйтесь вперёд.

На выдохе мощным усилием левой ноги вытолкните себя вверх, возвращаясь в исходное положение, и приставьте правую ногу. Затем повторите на другую ногу. Темп: 2 секунды вниз, 1 секунда вверх. Дыхание: вниз — вдох, вверх — выдох.

Главные ошибки: переднее колено уходит за носок (перегрузка сустава); наклон корпуса вперёд (снимает нагрузку с ягодиц); «проваливание» таза в сторону (нестабильность); толчок задней ногой (правильно — работа передней). Для облегчения делайте выпады без касания коленом пола (неглубокие) или держитесь рукой за стену/стул. Для усложнения возьмите в каждую руку по бутылке с водой.', 10, 4, '/exercises/reverse-lunge.gif', 'home', 0.9, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Подъемы на носки', 'lower_body', 'Подъёмы на носки стоя — изолированное упражнение для развития икроножных мышц (гастронемеуса) и камбаловидной мышцы. Сильные икры важны для бега, прыжков и устойчивости при ходьбе. Упражнение легко выполнять дома, используя любую устойчивую опору.

Встаньте прямо, ноги на ширине плеч, стопы параллельно. Для баланса слегка коснитесь рукой стены, спинки стула или другого устойчивого предмета. Корпус прямой, пресс напряжён, плечи опущены. Вес тела равномерно распределён на обе ноги.

На выдохе плавно поднимитесь на носки как можно выше, чувствуя сильное сокращение икр. В верхней точке сделайте паузу на 1 секунду, дополнительно напрягая мышцы. Не раскачивайтесь корпусом — движение только в голеностопных суставах.

На вдохе так же плавно опуститесь вниз, но не до конца: не касайтесь пятками пола, оставляйте напряжение в икрах. Это обеспечивает постоянную нагрузку. Темп: 2 секунды вверх, пауза 1 секунда, 2 секунды вниз.

Главные ошибки: раскачка корпусом (помощь инерцией); слишком быстрое опускание (потеря контроля); полное расслабление в нижней точке (снижает эффективность); подъём на носках без опоры (потеря равновесия). Для увеличения нагрузки выполняйте подъёмы на одной ноге (держась за опору). Для ещё большей сложности возьмите в руку бутылку с водой или рюкзак с грузом. Если есть ступенька или толстая книга, вставайте на неё носками, опуская пятки ниже уровня опоры — это увеличит амплитуду и растяжение.', 20, 4, '/exercises/calf-raise.gif', 'home', 0.15, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Махи ногами вперед', 'lower_body', 'Махи ногами вперёд — динамическое упражнение для разминки и укрепления сгибателей бедра (подвздошно-поясничной мышцы), а также для улучшения подвижности тазобедренного сустава. Подготавливает ноги к приседаниям и выпадам, часто используется в разминочной части тренировки.

Встаньте прямо, ноги на ширине таза. Для опоры слегка коснитесь одной рукой стены или спинки стула. Свободную руку держите на поясе или вытяните в сторону для баланса. Корпус прямой, пресс напряжён, взгляд вперёд.

На выдохе плавно поднимите одну ногу вперёд, сгибая её в колене или сохраняя почти прямой — чем прямее нога, тем сложнее и больше растяжение. Поднимайте ногу до комфортной высоты (обычно до уровня бедра, но не за счёт наклона корпуса назад). В верхней точке сделайте паузу 0.5 секунды.

На вдохе плавно опустите ногу, контролируя движение. Выполните нужное количество повторений на одну ногу, затем смените ногу. Темп: 1–2 секунды на подъём, 1–2 секунды на опускание.

Главные ошибки: наклон корпуса назад (компенсация), отрыв опорной пятки от пола, слишком быстрые рывковые махи (работает инерция), раскачка туловищем. Для облегчения слегка сгибайте опорную ногу в колене. Для усложнения добавьте небольшие утяжелители на лодыжки или выполняйте махи без опоры.', 12, 4, '/exercises/leg-swing.gif', 'home', 0.48, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Ягодичный мостик', 'lower_body', 'Ягодичный мостик — эффективное изолированное упражнение для активации и укрепления ягодичных мышц, задней поверхности бедра и мышц кора. Безопасно для поясницы и коленей, помогает улучшить осанку, уменьшить боли в пояснице и сформировать округлые ягодицы.

Лягте на спину на коврик, ноги согнуты в коленях, стопы плотно стоят на полу на ширине таза. Пятки должны быть на расстоянии примерно 15–20 см от ягодиц — так, чтобы при подъёме колени образовывали 90-градусный угол. Руки лежат вдоль тела ладонями вниз, либо скрещены на груди. Плечи прижаты к полу, лопатки сведены, поясница нейтральна (естественный небольшой прогиб).

На выдохе мощным усилием ягодиц поднимите таз вверх, отрывая поясницу от пола. В верхней точке тело должно образовывать прямую линию от плеч до коленей. Не прогибайтесь в пояснице — подъём идёт за счёт сжатия ягодиц. Задержитесь в верхней точке, максимально напрягая ягодицы.

На вдохе плавно опустите таз вниз, но не кладите его на пол полностью — оставьте лёгкое касание или контрольное напряжение. Это сохранит нагрузку в мышцах. Темп: 2 секунды на подъём, пауза 1–2 секунды, 2 секунды на опускание.

Главные ошибки: подъём таза за счёт поясницы (гиперлордоз), а не ягодиц — часто при отрыве лопаток от пола или запрокидывании головы; разведение коленей в стороны; стопы слишком далеко от ягодиц (включает бицепс бедра) или слишком близко (трудно поднимать); отсутствие паузы в верхней точке. Для облегчения выполняйте мостик без паузы или с меньшей амплитудой. Для усложнения положите на живот рюкзак с грузом или делайте упражнение на одной ноге (вторую выпрямите вверх).', 15, 4, '/exercises/glute-bridge.gif', 'home', 0.35, 30);

-- Lower Body для начинающих (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Жим ногами в тренажере', 'lower_body', 'Жим ногами в тренажёре — базовое многосуставное упражнение для развития квадрицепсов, ягодичных мышц, бицепса бедра и приводящих мышц. Снимает нагрузку с позвоночника, что делает его идеальным для людей с болями в спине или восстанавливающихся. Тренажёр фиксирует траекторию движения.

Сядьте в тренажёр, плотно прижав спину и таз к спинке сиденья. Поясница не должна отрываться — естественный прогиб сохраняется. Ноги поставьте на платформу на ширине плеч или чуть шире, стопы параллельно или носки слегка развёрнуты наружу. Чем выше стопы на платформе, тем больше работают ягодицы; чем ниже — тем больше квадрицепсы. Убедитесь, что колени при сгибании не выходят за линию стоп и движутся в одной плоскости. Руки держитесь за поручни, голову прижмите к спинке.

На вдохе медленно согните ноги, опуская платформу к себе, пока угол в коленях не достигнет 90 градусов (или чуть острее, если позволяет подвижность). Не опускайте платформу слишком низко — это перегружает коленные суставы и может округлить поясницу. Контролируйте движение, не бросайте вес.

На выдохе мощным усилием ног выжмите платформу вверх, но не блокируйте колени в верхней точке — оставьте микросгиб. Движение плавное, без рывков. Темп: 2–3 секунды вниз, 1–2 секунды вверх. Дыхание: опускание — вдох, подъём — выдох.

Главные ошибки: отрыв таза и поясницы от спинки (риск травмы позвоночника); сведение коленей внутрь или разведение наружу; блокировка коленей вверху; слишком глубокая амплитуда (пятки отрываются). Для акцента на ягодицы ставьте стопы выше и шире, для квадрицепсов — ниже и уже.', 15, 4, '/exercises/leg-press.gif', 'gym', 0.58, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Сгибание ног лежа', 'lower_body', 'Сгибание ног лёжа — изолированное упражнение для проработки бицепса бедра (задней поверхности бедра). Развитие этой мышцы важно для баланса ног, предотвращения травм коленей и улучшения результатов в беге и прыжках.

Лягте лицом вниз на скамью тренажёра так, чтобы колени свешивались чуть ниже края, а валики для ног находились чуть выше пяток (на уровне ахиллова сухожилия). Ноги выпрямлены в старте. Корпус плотно прилегает к скамье, таз не отрывается. Руками упритесь в поручни или возьмитесь за ручки. Голову можно повернуть набок или держать прямо.

На выдохе мощным движением согните ноги, подтягивая валики к ягодицам, до угла в колене примерно 90 градусов (или чуть острее). В верхней точке сделайте паузу, максимально напрягая бицепс бедра. Не бросайте вес, не используйте инерцию.

На вдохе медленно и подконтрольно верните ноги в исходное положение, полностью выпрямляя колени, но не выключая суставы. Темп: 2 секунды на сгибание, пауза 1 секунда, 3 секунды на разгибание.

Главные ошибки: отрыв таза от скамьи (читинг); слишком быстрый подъём (рывок); неполная амплитуда; сгибание ног с повёрнутыми наружу стопами (меняет акцент). Для усложнения выполняйте упражнение поочерёдно каждой ногой.', 15, 4, '/exercises/leg-curl.gif', 'gym', 0.4, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Разгибание ног сидя', 'lower_body', 'Разгибание ног сидя — изолированное упражнение для укрепления квадрицепсов (передней поверхности бедра). Часто используется для «добивки» мышц после базовых упражнений, а также в реабилитации коленного сустава.

Сядьте в тренажёр, плотно прижав спину к спинке. Голень уприте в нижний валик (над стопой). Руки держитесь за поручни. Ноги согнуты под прямым углом, колени на уровне края сиденья. Поясница не отрывается от спинки. Носки можно вытянуть прямо или слегка развернуть наружу.

На выдохе мощным движением выпрямите ноги до угла чуть менее 180 градусов, не блокируя колени. В верхней точке сделайте паузу, максимально напрягая квадрицепс. Движение только в коленном суставе, корпус неподвижен.

На вдохе медленно и контролируемо верните ноги в исходное положение, но не сбрасывайте вес в нижней точке — оставьте напряжение. Темп: 1–2 секунды на подъём, пауза 1–2 секунды, 2–3 секунды на опускание.

Главные ошибки: отрыв спины от спинки (помощь корпусом); слишком быстрый подъём (рывок); выключение коленей в верхней точке; подъём ног с помощью бёдер. Упражнение не рекомендуется при травмах коленей без консультации с врачом.', 15, 4, '/exercises/leg-extension.gif', 'gym', 0.42, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Приседания с гантелями', 'lower_body', 'Приседания с гантелями (гоблет-приседания или с двумя гантелями) — базовое упражнение для развития квадрицепсов, ягодиц и кора. Гантели смещают центр тяжести вперёд, помогая держать корпус вертикально и снижая нагрузку на поясницу.

Встаньте прямо, ноги на ширине плеч, носки чуть развёрнуты наружу. Возьмите одну гантель вертикально за один диск (как кубок) и держите её обеими руками у груди, локти вниз. Или возьмите по гантели в каждую руку и опустите их вдоль туловища. Спина прямая, лопатки сведены, пресс напряжён. Взгляд вперёд.

На вдохе начните приседать, отводя таз назад и сгибая колени. Следите, чтобы колени не заваливались внутрь и не выходили сильно вперёд за носки. Спину держите прямой. Опускайтесь до параллели бедра с полом или чуть ниже, если позволяет гибкость. Пятки не отрывайте.

На выдохе мощным усилием ног выпрямитесь, возвращаясь в исходное положение. В верхней точке не блокируйте колени. Темп: 2–3 секунды вниз, 1–2 секунды вверх. Дыхание: вниз — вдох, вверх — выдох.

Главные ошибки: округление спины (сутулость), сведение коленей внутрь, отрыв пяток, сильный наклон корпуса вперёд. Для облегчения приседайте неглубоко. Для усложнения увеличьте вес гантелей или выполняйте приседания с паузой в нижней точке.', 12, 4, '/exercises/goblet-squat.gif', 'gym', 0.98, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады с гантелями', 'lower_body', 'Выпады вперёд с гантелями — функциональное упражнение для ягодиц, квадрицепсов и мышц-стабилизаторов. Тренирует баланс и координацию, помогает исправить мышечный дисбаланс между ногами.

Встаньте прямо, ноги на ширине таза. Возьмите в каждую руку по гантели, руки опущены вдоль туловища. Корпус прямой, пресс напряжён, взгляд вперёд. Сделайте шаг вперёд одной ногой так, чтобы расстояние между стопами было чуть больше шага — при опускании оба колена должны сгибаться под 90 градусов.

На вдохе согните обе ноги, опуская заднее колено почти до пола (на 2–3 см выше). Переднее колено над пяткой, не выходит за носок. Корпус вертикально. Заднее бедро почти параллельно полу.

На выдохе мощным усилием передней ноги вытолкните себя вверх, возвращаясь в исходное положение. Затем повторите на другую ногу (поочерёдно или все повторения на одну ногу, потом на другую). Темп: 2 секунды вниз, 1 секунда вверх.

Главные ошибки: переднее колено уходит за носок, заднее колено ударяется об пол, наклон корпуса вперёд, раскачка корпусом. Для облегчения делайте выпады без гантелей или держась за опору. Для усложнения берите больший вес или выполняйте выпады с шагом назад (меньше нагрузка на колени).', 10, 4, '/exercises/dumbbell-lunge.gif', 'gym', 1.25, 60);

-- Lower Body для начинающих (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Приседания у стены', 'lower_body', 'Приседания у стены (стенка, wall sit) — статическое упражнение, развивающее выносливость квадрицепсов, ягодиц и кора. Ноги работают в изометрическом режиме, что укрепляет суставы и связки. Упражнение безопасно для спины и коленей.

Встаньте спиной к стене на расстоянии шага. Прислонитесь к стене всей спиной — от лопаток до ягодиц. Ноги на ширине плеч, ступни выдвините вперёд на 40–60 см от стены. Медленно съезжайте спиной вниз, сгибая колени, пока они не согнутся под углом 90 градусов. Бёдра параллельны полу, колени строго над пятками. Руки можно держать на бёдрах или вытянуть вперёд.

Зафиксируйте положение. Пресс напряжён, поясница прижата к стене. Сохраняйте неподвижность, дышите ровно — носом вдох, ртом выдох. Удерживайте позу как можно дольше.

Главные ошибки: колени выходят за носки (перенесите ступни дальше от стены); поясница отрывается от стены (слабость кора); задержка дыхания; округление плеч. Для облегчения держите угол в коленях 100–110 градусов (менее глубоко). Для усложнения возьмите в руки бутылки с водой или поднимите одну ногу вперёд.', 15, 4, '/exercises/wall-sit.gif', 'street', 0.42, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады на месте', 'lower_body', 'Выпады на месте (статические выпады) — упражнение для ягодиц и квадрицепсов с фиксированной позицией ног. Не нужно сохранять равновесие при движении, что упрощает технику и позволяет сконцентрироваться на работе мышц.

Встаньте в расстановку ног как при выпаде: одна нога впереди, другая сзади на расстоянии примерно 70–80 см. Переднее колено над пяткой, заднее — на носке. Корпус прямой, пресс напряжён, руки на поясе или опущены. Взгляд вперёд.

На вдохе согните оба колена, опуская заднее колено почти до пола (на 2–3 см выше). Переднее колено сгибается до 90 градусов, не выходя за носок. Корпус вертикально.

На выдохе мощным усилием передней ноги выпрямитесь, возвращаясь в исходное положение. Выполните все повторения на одну ногу, затем поменяйте ноги. Темп: 2 секунды вниз, 1 секунда вверх. Дыхание: вниз — вдох, вверх — выдох.

Главные ошибки: переднее колено выходит за носок; корпус наклоняется вперёд; заднее колено ударяется об пол; таз «проваливается» в сторону. Для облегчения делайте неглубокие выпады или держитесь за опору. Для усложнения возьмите в руки бутылки с водой или рюкзак с грузом.', 12, 4, '/exercises/stationary-lunge.gif', 'street', 0.69, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Зашагивания на скамью', 'lower_body', 'Зашагивания на скамью — функциональное упражнение для ягодиц, квадрицепсов и мышц-стабилизаторов, имитирующее подъём по лестнице. В уличных условиях используется любая устойчивая возвышенность (скамья, парапет, ступенька). Высота регулирует сложность: чем выше, тем тяжелее.

Встаньте перед скамьёй на расстоянии 15–20 см. Спина прямая, пресс напряжён, взгляд вперёд. Поставьте одну ногу полностью на скамью. Руки можно держать на поясе или свободно опустить.

На выдохе, опираясь на ногу, стоящую на скамье, поднимитесь вверх, полностью выпрямляя ногу и приставляя вторую. Не отталкивайтесь ногой, стоящей на полу — движение за счёт рабочей ноги.

На вдохе медленно и подконтрольно вернитесь в исходное положение, опуская сначала ту же ногу, которая была рабочей, затем вторую. Выполните все повторения на одну ногу, затем смените ногу. Темп: 2 секунды на подъём, 2 секунды на опускание.

Главные ошибки: толчок ногой, стоящей на земле; наклон корпуса вперёд; слишком низкая скамья (снижает эффективность); опускание с ударом. Для облегчения выбирайте низкую скамью (15–20 см) или держитесь рукой за стену. Для усложнения возьмите гантели или бутылки в руки.', 10, 4, '/exercises/step-up.gif', 'street', 1.1, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Приседания с выпрыгиванием', 'lower_body', 'Приседания с выпрыгиванием (прыжковые приседания) — плиометрическое упражнение для развития взрывной силы ног, сжигания калорий и выносливости. Подходит для подготовленных без проблем с коленями.

Встаньте прямо, ноги на ширине плеч, носки чуть развёрнуты. Руки согнуты в локтях или свободны. Опуститесь в обычный присед (бёдра параллельно полу или чуть выше), спина прямая, пятки на полу.

На выдохе резко выпрыгните вверх из приседа, взмахивая руками для инерции. Направьте выпрыгивание вверх, не вперёд.

Приземляйтесь мягко на носки с перекатом на всю стопу, сразу амортизируя колени. Сразу переходите в следующий присед. Темп непрерывный.

Главные ошибки: жёсткое приземление на прямые ноги; недостаточно глубокий присед; колени заваливаются внутрь; отрыв пяток до прыжка. Для облегчения делайте прыжки с минимальной амплитудой или обычные приседания без прыжка. Для усложнения увеличивайте высоту прыжка или берите гантели.', 10, 4, '/exercises/jump-squat.gif', 'street', 1.2, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады в сторону', 'lower_body', 'Выпады в сторону (боковые выпады) — упражнение для приводящих мышц бедра (внутренней поверхности), ягодиц и квадрицепсов. Улучшает подвижность тазобедренных суставов, помогает профилактировать травмы паха.

Встаньте прямо, ноги шире плеч (примерно в 1.5 раза), носки смотрят вперёд или чуть развёрнуты. Руки на поясе или вытянуты вперёд. Корпус прямой, пресс напряжён.

На вдохе перенесите вес на одну ногу, сгибая её в колене и отводя таз назад. Другая нога остаётся прямой, стопа полностью на полу. Сгибаемая нога до угла примерно 90 градусов, колено не выходит за носок. Таз опускается вниз и назад, корпус слегка наклоняется вперёд (но спина прямая).

На выдохе мощным усилием согнутой ноги вернитесь в исходное положение. Затем повторите в другую сторону. Темп: 2 секунды вниз, 1 секунда вверх.

Главные ошибки: сгибаемая нога отрывает пятку; колено заваливается внутрь; спина округляется; сильный наклон корпуса вперёд. Для облегчения делайте неглубокие выпады или держитесь за опору. Для усложнения возьмите к груди одну гантель (гоблет) или по гантели в каждую руку.', 10, 4, '/exercises/side-lunge.gif', 'street', 0.95, 40);

-- Full Body для начинающих (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Берпи без прыжка', 'full_body', 'Берпи без прыжка — упрощённая версия классического берпи. Упражнение развивает выносливость, координацию и задействует почти все мышцы тела: грудь, плечи, трицепс, пресс, ягодицы и ноги. Отсутствие прыжка снижает ударную нагрузку на колени и позвоночник.

Встаньте прямо, ноги на ширине плеч, руки опущены. На выдохе присядьте и поставьте ладони на пол перед собой. Прыжком или шагом переведите ноги назад в планку — тело прямое от пяток до макушки, пресс напряжён, поясница не прогибается.

В планке сделайте одно отжимание от пола (грудь касается пола или опускается максимально низко, локти 45°). Если тяжело — опустите колени. После отжимания прыжком или шагом подтяните ноги обратно к рукам, вернувшись в глубокий присед. На выдохе встаньте, выпрямляя корпус. Это одно повторение.

Темп плавный, без рывков. Дыхание: на отжимании — вдох (вниз) и выдох (вверх), при подтягивании ног — выдох, при вставании — выдох. Главные ошибки: провисшая поясница в планке, неполное отжимание, округление спины при подтягивании ног, задержка дыхания. Для облегчения исключите отжимание (только переходы) или делайте движение шагом вместо прыжков. Для усложнения добавьте небольшой прыжок в конце или ускорьте темп.', 8, 4, '/exercises/burpee-no-jump.gif', 'home', 1.25, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Медвежья походка', 'full_body', 'Медвежья походка (bear crawl) — функциональное упражнение для мышц кора, плечевого пояса, спины, рук и ног, а также для координации. Выполняется на четвереньках с прямыми ногами и спиной, имитируя походку медведя.

Встаньте на четвереньки: ладони под плечами, колени под тазом. Выпрямите ноги, подняв колени на 5–10 см от пола, чтобы оставаться на руках и носках. Спина прямая (нейтральный позвоночник), таз не поднимайте высоко, не прогибайте поясницу. Голова — продолжение позвоночника, взгляд в пол.

Сохраняя прямую спину, сделайте шаг вперёд правой рукой и левой ногой одновременно (перекрёстный паттерн). Затем шаг левой рукой и правой ногой. Продолжайте двигаться вперёд. Дыхание ровное. Темп медленный, контролируемый.

Главные ошибки: прогиб или округление спины, подъём таза вверх, отрыв стоп от пола (опора на колени), слишком быстрые рывки. Для облегчения делайте походку с опорой на колени (не отрывая их). Для усложнения двигайтесь быстрее, добавьте отягощение на спину или выполняйте со смещением вбок.', 10, 4, '/exercises/bear-crawl.gif', 'home', 0.85, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Ситапы', 'full_body', 'Ситапы (полные подъёмы корпуса) — классическое упражнение для прямой мышцы живота и сгибателей бедра. Отличие от скручиваний — отрыв поясницы от пола и полный подъём корпуса до касания грудью коленей. Требует осторожности при слабой пояснице.

Лягте на спину, ноги согните в коленях, стопы на полу на ширине таза. Руки за головой или скрещены на груди. Можно зафиксировать ступни, но это уменьшает нагрузку на пресс (лучше без фиксации). Шея расслаблена.

На выдохе мощным усилием пресса поднимите корпус, округляя спину, отрывая поясницу, пока не коснётесь локтями или грудью коленей. Движение плавное, без рывка. В верхней точке пауза.

На вдохе медленно и контролируемо опуститесь вниз, позвонок за позвонком, до касания лопатками пола. Не расслабляйте пресс в нижней точке. Темп: 2 секунды подъём, пауза, 2 секунды опускание.

Главные ошибки: рывки головой и руками (тянут шею), отрыв пяток, слишком быстрое опускание, округление спины в грудном отделе (нужно скручивание). При болях в пояснице выполняйте неполные ситапы (подъём до 45 градусов) или замените на скручивания. Для усложнения держите гантель у груди или выпрямляйте ноги под углом 45°.', 15, 4, '/exercises/situp.gif', 'home', 0.43, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Планка с подъемом ноги', 'full_body', 'Планка с попеременным подъёмом ноги — динамическое упражнение, усложняющее классическую планку. Усиливает нагрузку на кор (особенно поперечную мышцу), ягодицы, заднюю поверхность бедра, развивает баланс и стабильность.

Примите планку на прямых руках (ладони под плечами) или на предплечьях. Тело — прямая линия от пяток до макушки. Пресс напряжён, поясница не прогибается, таз фиксирован.

На выдохе медленно поднимите одну ногу вверх на 15–20 см (не выше таза), сохраняя корпус неподвижным. Нога прямая или чуть согнута. Медленно опустите. Затем повторите другой ногой. Темп: 2 секунды подъём, пауза, 2 секунды опускание.

Главные ошибки: провисание поясницы (живот «течёт» вниз), подъём таза вверх, раскачивание корпуса. Если сложно, делайте планку на предплечьях. Для облегчения поднимайте ногу всего на 5–10 см. Для усложнения задерживайтесь в верхней точке дольше или добавьте утяжелители на лодыжки.', 10, 4, '/exercises/plank-leg-lift.gif', 'home', 0.7, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады с поворотом', 'full_body', 'Выпады с поворотом корпуса — многофункциональное упражнение: работа ног (ягодицы, квадрицепсы) и вращательное движение для мышц кора (косые мышцы). Также задействуются плечи и грудь, если использовать отягощение.

Встаньте прямо, ноги на ширине таза, руки перед грудью в замке или держите одну бутылку воды двумя руками. Корпус прямой, пресс напряжён. Сделайте шаг вперёд правой ногой в выпад — опуститесь так, чтобы правое колено было согнуто под 90 градусов, левое почти касалось пола.

В нижней точке, не меняя положения ног, плавно поверните корпус в сторону правой выпадающей ноги. Руки двигаются вместе с корпусом. Таз остаётся неподвижным. Вернитесь в центр.

На выдохе оттолкнитесь правой ногой и вернитесь в исходное положение. Затем повторите на левую ногу. Темп медленный, контролируемый.

Главные ошибки: наклон корпуса вперёд или назад при повороте, вращение таза, потеря равновесия, колено передней ноги выходит за носок. Для облегчения делайте выпады на месте (статические) и выполняйте поворот в комфортной амплитуде. Для усложнения возьмите гантель или бутылку и вытягивайте руку в сторону.', 10, 4, '/exercises/lunge-twist.gif', 'home', 0.9, 30);

-- Full Body для начинающих (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Становая тяга', 'full_body', 'Становая тяга — базовое многосуставное упражнение, задействующее почти все мышцы: разгибатели спины, ягодицы, бицепс бедра, квадрицепсы, трапеции, предплечья и кор. Выполняется с небольшим весом для отработки техники.

Подойдите к штанге на полу. Ноги на ширине таза, гриф над серединой стопы. Наклонитесь с прямой спиной, возьмите штангу хватом чуть шире плеч (можно разноимённым). Лопатки сведены, плечи чуть впереди грифа. Таз ниже плеч, спина прямая.

На выдохе мощным усилием ног поднимите штангу, выпрямляя колени и таз. Гриф скользит вдоль голеней и бёдер. В верхней точке выпрямитесь, отведите плечи назад, не прогибайтесь.

На вдохе медленно опустите штангу, контролируя движение: сначала таз назад, затем сгибание коленей, гриф скользит вниз. Темп: 2–3 секунды подъём, пауза, 3–4 секунды опускание.

Главные ошибки: округление спины, рывок, подъём таза быстрее плеч, отрыв грифа от ног, выключение коленей вверху, взгляд вверх. Начинайте с пустого грифа или лёгких гантелей, отрабатывайте технику перед зеркалом.', 10, 4, '/exercises/deadlift.gif', 'gym', 1.8, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Приседания со штангой', 'full_body', 'Приседания со штангой на спине — классика для квадрицепсов, ягодиц и кора. Выполняется с пустым грифом или небольшим весом, часто в силовой раме.

Подойдите к штанге на стойках чуть ниже плеч. Присядьте под гриф, положите на трапеции (не на шею), сведите лопатки. Возьмитесь широким хватом. Снимите штангу, шаг назад. Ноги на ширине плеч, носки чуть развёрнуты.

На вдохе приседайте, отводя таз назад, колени в направлении носков. Спина прямая. Опускайтесь до параллели бедра с полом или чуть ниже. Пятки не отрывать. Пауза внизу.

На выдохе мощно выпрямитесь, не блокируя колени. Темп: 2–3 секунды вниз, пауза, 1–2 секунды вверх.

Главные ошибки: округление спины, колени уходят вперёд за носки, отрыв пяток, «подворачивание» таза. Если не получается держать спину прямо, уменьшите вес или приседайте неглубоко. Используйте силовую раму.', 10, 4, '/exercises/barbell-squat.gif', 'gym', 1.6, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Тяга верхнего блока к груди', 'full_body', 'Тяга верхнего блока к груди — базовое упражнение для широчайших мышц спины, бицепсов и задних дельт. Выполняется на блочном тренажёре.

Сядьте на скамью, зафиксируйте колени под валиками. Возьмитесь за рукоять широким прямым хватом (ладони от себя) чуть шире плеч. Спина прямая, лопатки сведены, пресс напряжён. Слегка отклоните корпус назад.

На выдохе без раскачки тяните рукоять к верхней части груди, сводя лопатки, локти вниз-назад. Пауза.

На вдохе медленно верните вверх до полного выпрямления рук, растягивая спину.

Главные ошибки: раскачка корпусом, тяга бицепсом (локти вперёд), опускание за голову или слишком низко, округление спины.', 12, 4, '/exercises/lat-pulldown.gif', 'gym', 0.75, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Жим гантелей лежа', 'full_body', 'Жим гантелей лёжа на горизонтальной скамье — базовое упражнение для грудных, передних дельт и трицепсов. Гантели дают большую амплитуду и снижают нагрузку на плечи по сравнению со штангой.

Лягте на скамью, ноги на полу. Лопатки сведены. Возьмите гантели и поднимите над грудью прямыми руками, ладони вперёд или друг к другу. Локти слегка согнуты.

На вдохе опустите гантели в стороны и немного вниз до уровня груди, локти под углом 45° к корпусу. Пауза.

На выдохе мощно выжмите вверх, сводя гантели.

Главные ошибки: разведение локтей в стороны (риск для плеч), отрыв таза от скамьи, слишком быстрый подъём, асимметрия.', 10, 4, '/exercises/dumbbell-bench-press.gif', 'gym', 1.2, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Тяга гантели в наклоне', 'full_body', 'Тяга гантели в наклоне (к поясу) — одностороннее упражнение для спины (широчайшие, ромбовидные, трапеции, бицепс). Помогает исправить мышечный дисбаланс.

Поставьте одно колено и одноимённую руку на горизонтальную скамью. Вторая нога на полу, спина прямая параллельно полу. Гантель в свободной руке нейтральным хватом.

На выдохе подтяните гантель к поясу, локоть вдоль туловища вверх-назад. Пауза вверху.

На вдохе медленно опустите до полного выпрямления руки. Затем на другую руку. Главные ошибки: округление спины, подъём плеча к уху, поворот корпуса, рывки. Для облегчения используйте меньший вес.', 12, 4, '/exercises/dumbbell-row.gif', 'gym', 0.83, 45);

-- Full Body для начинающих (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Подтягивания на низкой перекладине', 'full_body', 'Подтягивания на низкой перекладине (австралийские) — горизонтальные подтягивания с опорой ног на землю. Укрепляют широчайшие, бицепсы, задние дельты и кор.

Возьмитесь за перекладину хватом на ширине плеч. Ноги вытянуты вперёд, пятки на полу. Тело прямое от пяток до макушки. Пресс напряжён, лопатки сведены.

На выдохе подтяните грудную клетку к перекладине, сводя лопатки, локти вдоль корпуса. Старайтесь коснуться перекладины верхней частью груди. Пауза.

На вдохе медленно опуститесь до полного выпрямления рук. Не раскачивайтесь. Темп: 2 секунды подъём, пауза, 3 секунды опускание.

Главные ошибки: прогиб в пояснице, подъём плеч к ушам, раскачка. Для облегчения поставьте ноги ближе к перекладине (тело вертикальнее). Для усложнения — ноги на возвышение.', 8, 4, '/exercises/australian-pullup.gif', 'street', 1.63, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отжимания от скамьи с подъемом ноги', 'full_body', 'Отжимания от скамьи с попеременным подъёмом ноги — усложнённый вариант, добавляющий работу кора и ягодиц. Выполняется на устойчивой скамье (40–60 см).

Поставьте руки на край скамьи чуть шире плеч, ноги назад на полу. Корпус прямой, пресс напряжён. Тело под углом 30–45°.

Выполните отжимание: на вдохе согните локти (45°), опуская грудь к скамье; на выдохе выжмитесь. В верхней точке поднимите одну ногу вверх на 15–20 см, задержитесь, опустите. Следующее отжимание — с другой ногой.

Главные ошибки: прогиб поясницы при подъёме ноги, неполное отжимание. Для облегчения сначала освойте обычные отжимания от скамьи.', 8, 4, '/exercises/bench-pushup-leg-lift.gif', 'street', 1.25, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Берпи на скамье', 'full_body', 'Берпи на скамье — облегчённый вариант берпи, где скамья служит опорой. Упражнение задействует всё тело, развивает выносливость.

Встаньте лицом к скамье (40–50 см). Присед, ладони на скамью. Прыжком или шагом отведите ноги назад в планку. Зафиксируйте. Прыжком или шагом подтяните ноги обратно. Выпрямитесь, руки вверх (без прыжка). Это одно повторение.

Можно добавить небольшой прыжок после вставания. Темп умеренный. Главные ошибки: провисшая поясница в планке, потеря контроля. Для облегчения делайте шагом. Для усложнения добавьте отжимание от скамьи в нижней точке.', 8, 4, '/exercises/bench-burpee.gif', 'street', 1.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Зашагивания на скамью с махом', 'full_body', 'Зашагивания на скамью с махом рук — функциональное упражнение для ног, плеч и координации.

Встаньте перед скамьёй (30–50 см). Поставьте правую ногу на скамью. На выдохе оттолкнитесь, поднимитесь, одновременно мах руками вверх. В верхней точке левую ногу подтяните коленом вверх или приставьте. Задержитесь.

На вдохе опуститесь. Чередуйте ноги. Темп: 2 секунды подъём, 2 секунды опускание.

Главные ошибки: толчок ногой на земле, наклон корпуса, жёсткое опускание. Для облегчения используйте низкую скамью и без маха. Для усложнения возьмите гантели.', 10, 4, '/exercises/step-up-arm-swing.gif', 'street', 1.1, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Выпады с опорой на скамью', 'full_body', 'Выпады назад с опорой на скамью — безопасная версия, где задняя нога на скамье, что уменьшает нагрузку на колено.

Встаньте спиной к скамье на расстоянии шага. Поставьте подъём правой ноги на скамью. Левая нога впереди, стопа на полу. Корпус прямой.

На вдохе согните левую ногу до 90°, опуская таз. Правое колено сгибается, не касаясь пола. Пауза.

На выдохе выпрямитесь. Выполните все повторения на одну ногу, затем поменяйте.

Главные ошибки: переднее колено выходит за носок, наклон корпуса вперёд. Для облегчения используйте более высокую скамью. Для усложнения возьмите гантели.', 10, 4, '/exercises/bench-lunge.gif', 'street', 1.05, 30);

-- Cardio для начинающих (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Бег на месте', 'cardio', 'Бег на месте с высоким подниманием коленей — эффективное кардио для разогрева и сжигания калорий. Высокий подъём коленей нагружает сгибатели бедра и кор.

Встаньте прямо, ноги на ширине таза, руки согнуты в локтях. Бегите на месте, высоко поднимая колени до уровня таза. Приземляйтесь на носок, потом на всю стопу. Дышите ритмично. Темп средний или быстрый.

Главные ошибки: приземление на пятку, наклон корпуса назад, опущенная голова. Для облегчения поднимайте колени ниже. Для усложнения ускоряйтесь.', 30, 4, '/exercises/high-knees.gif', 'home', 8.5, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Прыжки с разведением рук и ног', 'cardio', 'Прыжки с разведением рук и ног (Jumping Jacks) — классическое аэробное упражнение для всего тела.

Встаньте прямо, ноги вместе, руки вдоль тела. Прыжком расставьте ноги на ширину плеч и поднимите руки вверх. Прыжком вернитесь. Дышите: разведение — вдох, сведение — выдох. Приземляйтесь мягко.

Главные ошибки: жёсткое приземление, неполное разведение рук. Для облегчения делайте шагом. Для усложнения ускорьте темп или добавьте хлопок.', 20, 4, '/exercises/jumping-jacks.gif', 'home', 7.0, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Скалолаз в медленном темпе', 'cardio', 'Скалолаз в медленном темпе — динамическое упражнение для выносливости, кора, плеч и ног.

Примите упор лёжа, тело прямое. Поочерёдно подтягивайте колени к груди в медленном темпе (около 1 движения в секунду). Таз не поднимайте.

Главные ошибки: прогиб или округление спины, подъём таза. Для облегчения делайте с опорой на колени. Для усложнения ускорьте темп.', 20, 4, '/exercises/mountain-climber.gif', 'home', 9.5, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Боксирование с тенью', 'cardio', 'Боксирование с тенью — имитация ударов руками. Развивает координацию, скорость, выносливость.

Встаньте в боксёрскую стойку, кулаки у подбородка. Наносите прямые удары, апперкоты, хуки. Двигайтесь на носках. Дыхание: выдох на ударе.

Главные ошибки: полностью выпрямленные локти, опущенные кулаки, отсутствие движения ног. Для облегчения делайте только руками. Для усложнения добавьте уклоны.', 30, 4, '/exercises/shadow-boxing.gif', 'home', 6.5, 15),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Отведение ног назад в прыжке', 'cardio', 'Прыжки с захлёстом голени — для разогрева задней поверхности бедра.

Бегите на месте, стараясь пятками касаться ягодиц. Колени вниз, корпус слегка наклонён вперёд. Дышите ритмично.

Главные ошибки: наклон корпуса назад, слабое сгибание ног. Для облегчения делайте шагом без прыжка. Для усложнения ускорьте темп.', 25, 4, '/exercises/butt-kicks.gif', 'home', 7.5, 15);

-- Cardio для начинающих (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Ходьба на беговой дорожке', 'cardio', 'Ходьба на беговой дорожке с небольшим наклоном — безопасное кардио для суставов.

Встаньте на дорожку, держитесь за поручни только для баланса. Ходите со скоростью 4–5 км/ч, наклон 1–3%. Спина прямая, руки работают. Дышите ровно.

Главные ошибки: опора на поручни, наклон корпуса вперёд.', 30, 4, '/exercises/treadmill-walk.gif', 'gym', 5.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Велотренажер', 'cardio', 'Езда на велотренажёре в умеренном темпе — низкоударное кардио для ног и сердца.

Отрегулируйте сиденье. Крутите педали 60–80 об/мин, сопротивление минимальное. Спина прямая.

Главные ошибки: сутулость, опора на руль всем весом.', 30, 4, '/exercises/stationary-bike.gif', 'gym', 7.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Эллиптический тренажер', 'cardio', 'Ходьба на эллипсоиде имитирует бег без ударной нагрузки. Стопы в центре педалей. Двигайтесь, помогая руками. Дышите ровно. Главные ошибки: наклон корпуса вперёд, опора всем телом на поручни.', 30, 4, '/exercises/elliptical.gif', 'gym', 8.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Гребной тренажер', 'cardio', 'Гребля задействует более 80% мышц. Освойте фазы: захват, проводка (ноги-спина-руки), возврат. Держите спину прямой. Главные ошибки: округление спины, использование только рук.', 60, 4, '/exercises/rowing-machine.gif', 'gym', 9.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Степпер', 'cardio', 'Ходьба на степпере имитирует подъём по лестнице. Нажимайте на педали ногами, не раскачиваясь. Главные ошибки: опора на поручни, округление спины.', 30, 4, '/exercises/stepper.gif', 'gym', 6.5, 30);

-- Cardio для начинающих (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Бег трусцой', 'cardio', 'Лёгкий бег трусцой — аэробное упражнение на свежем воздухе. Начните с быстрой ходьбы, затем бегите в разговорном темпе. Спина прямая, руки согнуты. Главные ошибки: слишком длинный шаг, жёсткое приземление.', 60, 4, '/exercises/jogging.gif', 'street', 10.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Скандинавская ходьба', 'cardio', 'Ходьба с палками снижает нагрузку на колени. Палки ставьте с наклоном, отталкивайтесь через темляк. Главные ошибки: волочение палок, слишком маленький шаг.', 60, 4, '/exercises/nordic-walking.gif', 'street', 6.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Прыжки через скакалку', 'cardio', 'Прыжки на скакалке развивают выносливость и координацию. Вращайте кистями, прыгайте невысоко, на носках. Главные ошибки: жёсткое приземление, вращение плечами.', 50, 4, '/exercises/jump-rope.gif', 'street', 11.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Подъем по лестнице', 'cardio', 'Ходьба по лестнице нагружает ягодицы и сердце. Ступайте всей стопой, спина прямая. Руки свободно. Главные ошибки: опора на перила, перескакивание через ступеньку.', 30, 4, '/exercises/stairs.gif', 'street', 9.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Бег с высоким подниманием бедра', 'cardio', 'Бег на месте с высоким подъёмом коленей и продвижением вперёд. Продвигайтесь короткими быстрыми шагами. Главные ошибки: наклон корпуса назад, низкий подъём колена.', 30, 4, '/exercises/high-knees-street.gif', 'street', 9.5, 20);

-- Flexibility для начинающих (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Наклоны к ногам сидя', 'flexibility', 'Наклон к прямым ногам сидя растягивает заднюю поверхность бедра, поясницу и икры. Сядьте, ноги вместе. На вдохе вытянитесь вверх, на выдохе наклонитесь от таза, сохраняя спину прямой. Задержитесь, дышите ровно. Главные ошибки: округление спины, сгибание коленей. Для облегчения согните колени.', 10, 4, '/exercises/seated-forward-bend.gif', 'home', 3.5, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка квадрицепса стоя', 'flexibility', 'Растяжка квадрицепса стоя. Встаньте, одной рукой держитесь за опору. Согните ногу, притягивая пятку к ягодице. Колено вниз. Задержитесь. Главные ошибки: прогиб в пояснице, отведение колена в сторону.', 10, 4, '/exercises/standing-quad-stretch.gif', 'home', 3.0, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка грудных мышц', 'flexibility', 'Растяжка груди у стены. Встаньте сбоку, вытяните руку назад, опираясь ладонью о стену. Поверните корпус в противоположную сторону. Задержитесь. Главные ошибки: сгибание запястья, сильный поворот.', 8, 4, '/exercises/chest-stretch.gif', 'home', 2.8, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Поза ребенка', 'flexibility', 'Поза ребёнка — восстанавливающая поза для спины. Сядьте на пятки, на выдохе наклонитесь вперёд, лоб на пол, руки вперёд. Расслабьтесь. Главные ошибки: напряжение шеи, давление на пятки.', 5, 4, '/exercises/child-pose.gif', 'home', 2.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка трицепса', 'flexibility', 'Растяжка трицепса за головой. Поднимите руку вверх, согните за голову, другой рукой потяните локоть. Главные ошибки: наклон головы вперёд, рывки за локоть.', 8, 4, '/exercises/triceps-stretch.gif', 'home', 2.5, 15);

-- Flexibility для начинающих (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка на коврике', 'flexibility', 'Базовый комплекс растяжки: лёжа подтягивание колена к груди, растяжка бицепса бедра, поза кобры, сидячий наклон, скручивания, поза ребёнка. Каждое положение удерживайте. Главные ошибки: рывки, задержка дыхания.', 8, 4, '/exercises/mat-stretch.gif', 'gym', 4.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка с фитболом', 'flexibility', 'Растяжка спины на фитболе. Лягте животом на мяч, расслабьте спину. Для груди — лягте спиной на мяч, разведите руки. Главные ошибки: напряжение шеи, слишком большой мяч.', 6, 4, '/exercises/ball-stretch.gif', 'gym', 4.2, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Вис на перекладине', 'flexibility', 'Вис для растяжки позвоночника. Повисните на прямых руках, расслабьте тело, не раскачивайтесь. Главные ошибки: подъём плеч к ушам, задержка дыхания.', 3, 4, '/exercises/hanging-stretch.gif', 'gym', 3.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка с эспандером', 'flexibility', 'Растяжка рук и плеч с лентой. Разводите ленту руками, делайте замок за спиной, отводите ногу с лентой. Главные ошибки: рывки, боль.', 10, 4, '/exercises/band-stretch.gif', 'gym', 3.2, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'beginner', 'Растяжка на скамье', 'flexibility', 'Растяжка спины на скамье гиперэкстензии. Опускайте корпус вниз, чувствуя растяжение. Также растяжка груди поперёк скамьи. Главные ошибки: резкие движения, глубокий прогиб при болях.', 6, 4, '/exercises/bench-stretch.gif', 'gym', 3.3, 20);

-- Flexibility для начинающих (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
    (gen_random_uuid(), 'beginner', 'Растяжка на турнике', 'flexibility', 'Вис на турнике с расслаблением для позвоночника. Повисните, полностью расслабьтесь, не раскачивайтесь. Главные ошибки: напряжение в плечах, сжатие перекладины.', 3, 4, '/exercises/bar-hang.gif', 'street', 3.2, 30);
-- ==================== УПРАЖНЕНИЯ ДЛЯ СРЕДНЕГО УРОВНЯ (medium) ====================

-- Upper Body для среднего уровня (home) — техника без упоминания уровня и объёмов
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Классические отжимания', 'upper_body',
                                                                                                                                                                                  'Классические отжимания в упоре лёжа — базовое упражнение для развития грудных мышц, трицепсов и передних дельт. Примите упор лёжа: ладони на полу строго под плечами или чуть шире, пальцы смотрят вперёд или слегка наружу. Ноги на носках, стопы вместе или на ширине таза. Тело образует прямую линию от пяток до макушки — пресс и ягодицы напряжены, поясница не прогибается, таз не поднимается. Локти при опускании движутся под углом примерно 45 градусов к корпусу, не разводите их в стороны (это травмирует плечи). На вдохе медленно согните руки, опуская грудь до касания пола (или на 2–3 см от пола). В нижней точке сделайте паузу на 0.5 секунды. На выдохе мощным усилием выжмите себя вверх, почти выпрямляя руки, но не блокируя локти. Темп: 2 секунды вниз, 1 секунда вверх. Главные ошибки: провисшая поясница («лодочка»), подъём таза вверх («горка»), неполная амплитуда, разведение локтей перпендикулярно телу. Для облегчения выполняйте с колен на полу. Для усложнения положите на спину рюкзак с грузом или используйте отягощение.',
                                                                                                                                                                                  12, 4, '/exercises/pushup.gif', 'home', 1.04, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания алмазные', 'upper_body',
                                                                                                                                                                                  'Алмазные отжимания — упражнение с узкой постановкой рук, акцентирующее нагрузку на трицепс и внутреннюю часть груди. Встаньте в упор лёжа, соедините указательные и большие пальцы обеих рук, образуя треугольник (ромб) под грудью. Локти при сгибании идут строго вдоль корпуса назад, не разводитесь. Тело прямое, поясница не провисает. На вдохе медленно опуститесь грудью к кистям, стараясь коснуться рук. На выдохе мощно выжмитесь вверх, полностью выпрямляя руки, но без блокировки локтей. Дыхание: вниз — вдох, вверх — выдох. Главные ошибки: разведение локтей в стороны (снижает нагрузку на трицепс), прогиб в пояснице, неполное выпрямление рук. Если сложно, выполняйте с колен. Для усложнения добавьте паузу в нижней точке или используйте рюкзак с грузом.',
                                                                                                                                                                                  10, 4, '/exercises/diamond-pushup.gif', 'home', 1.4, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания с ногами на возвышении', 'upper_body',
                                                                                                                                                                                  'Отжимания с ногами на стуле (или скамье) смещают нагрузку на верхнюю часть груди и передние дельты, увеличивая процент веса тела на руках. Поставьте ноги на устойчивый стул, руки на полу чуть шире плеч. Тело прямое, ягодицы напряжены, поясница не прогибается. На вдохе опустите грудь к полу, локти движутся под углом 45 градусов к корпусу. Не разводите локти в стороны. На выдохе мощно выжмитесь вверх, почти выпрямляя руки. Следите, чтобы таз не поднимался и не провисал. Главные ошибки: прогиб в пояснице (компенсация), подъём таза вверх, слишком широкая постановка локтей. Для облегчения уменьшите высоту опоры (например, невысокая скамья). Для усложнения увеличьте высоту или добавьте вес на спину.',
                                                                                                                                                                                  10, 4, '/exercises/decline-pushup.gif', 'home', 1.55, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания широким хватом', 'upper_body',
                                                                                                                                                                                  'Отжимания широким хватом (руки значительно шире плеч) акцентируют нагрузку на внешнюю часть грудных мышц. Примите упор лёжа, расставьте ладони в 1.5–2 раза шире плеч, пальцы смотрят в стороны или вперёд. Корпус прямой, пресс и ягодицы напряжены. На вдохе медленно согните руки, локти уходят в стороны под углом около 60–75 градусов. Опускайтесь до тех пор, пока грудь не окажется в 5–10 см от пола. Не разводите локти в линию «крыльев» (90 градусов) — это травмоопасно для плеч. На выдохе выжмитесь вверх, сводя лопатки. В верхней точке локти не блокируйте. Главные ошибки: провисание поясницы, слишком широкая постановка рук (боль дискомфорт в плечах), неполная амплитуда. Для облегчения выполняйте с колен. Для усложнения добавьте паузу в нижней точке.',
                                                                                                                                                                                  12, 4, '/exercises/wide-pushup.gif', 'home', 1.08, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания с поднятой ногой', 'upper_body',
                                                                                                                                                                                  'Отжимания с одной ногой на возвышении (пикой) увеличивают нагрузку на плечи и верх груди, а также требуют стабильности кора. Поставьте носок одной ноги на стул или скамью, другая нога остаётся на полу. Руки на полу чуть шире плеч. Тело прямое, таз не перекошен, пресс напряжён. На вдохе опустите грудь к полу, локти под 45 градусов. На выдохе мощно выжмитесь вверх. Следите, чтобы таз не «заваливался» в сторону опорной ноги. Выполните все повторения с одной поднятой ногой, затем смените ногу. Главные ошибки: перекос таза, прогиб в пояснице, неполная амплитуда. Для облегчения ставьте ногу на низкую опору. Для усложнения используйте более высокую опору или добавьте вес.',
                                                                                                                                                                                  10, 4, '/exercises/pike-pushup.gif', 'home', 1.45, 45);

-- Upper Body для среднего уровня (gym) — техника без упоминания уровня
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Жим штанги стоя', 'upper_body',
                                                                                                                                                                                  'Жим штанги стоя (армейский жим) — базовое упражнение для дельтовидных мышц (передний и средний пучки), трицепсов и верхней части груди. Встаньте прямо, штанга лежит на плечах перед грудью, хват чуть шире плеч. Локти смотрят вниз и чуть вперёд. Слегка согните колени для стабилизации, пресс и ягодицы напряжены, поясница сохраняет естественный прогиб (не переразгибайте). На выдохе мощно выжмите штангу вертикально вверх, слегка заводя голову назад, чтобы гриф прошёл перед лицом. В верхней точке руки почти прямые, но не блокируйте локти — оставьте микросгиб. На вдохе плавно опустите штангу к ключицам, контролируя движение. Не используйте ноги для толчка. Темп: 2 секунды вверх, 2–3 секунды вниз. Главные ошибки: прогиб в пояснице (компенсация за счёт спины), выталкивание ногами, опускание грифа слишком низко (на грудь, а не на ключицы), разведение локтей назад. Для облегчения используйте меньший вес. Для усложнения выполняйте жим стоя с паузой в нижней точке или добавьте вращение кистей.',
                                                                                                                                                                                  8, 4, '/exercises/standing-military-press.gif', 'gym', 2.25, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Тяга штанги в наклоне', 'upper_body',
                                                                                                                                                                                  'Тяга штанги в наклоне к поясу — базовое упражнение для широчайших, ромбовидных мышц, трапеций и бицепса. Наклоните корпус вперёд, сохраняя спину прямой (угол примерно 45 градусов к полу). Колени слегка согнуты, штанга висит на вытянутых руках, хват чуть шире плеч. Ладони смотрят назад (прямой хват). На выдохе тяните штангу к нижней части живота, сводя лопатки и ведя локти вдоль корпуса вверх и назад. В верхней точке сделайте паузу на 1 секунду, максимально напрягая спину. На вдохе медленно опустите штангу вниз до полного выпрямления рук, позволяя мышцам растянуться. Не округляйте спину и не поднимайте корпус вверх. Главные ошибки: округление спины (опасно для поясницы), рывок, подъём плеч к ушам, использование бицепса вместо спины. Для облегчения уменьшите вес. Для усложнения используйте обратный хват (ладони к себе) для усиления бицепса или выполняйте тягу с паузой в каждой точке.',
                                                                                                                                                                                  8, 4, '/exercises/bent-over-row.gif', 'gym', 2.06, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Жим гантелей на наклонной скамье', 'upper_body',
                                                                                                                                                                                  'Жим гантелей на наклонной скамье (угол 30–45 градусов) акцентирует нагрузку на верхнюю часть грудных мышц и передние дельты. Установите скамью с нужным наклоном. Лягте на неё, ноги плотно на полу на ширине плеч. Возьмите гантели нейтральным хватом (ладони друг к другу) или прямым (ладони от себя). Выжмите гантели над грудью, руки прямые, но локти не блокируйте. На вдохе медленно опустите гантели к верхней части груди, разводя локти в стороны под углом 45–60 градусов. Не опускайте гантели слишком низко (ниже уровня груди) — это травмирует плечи. В нижней точке сделайте паузу 0.5 секунды. На выдохе мощно выжмите гантели вверх по дуге, сводя их в исходное положение. Не стучите гантелями друг о друга. Главные ошибки: отрыв таза и поясницы от скамьи, слишком широкое разведение локтей (90 градусов), сгибание запястий назад. Для облегчения уменьшите вес. Для усложнения выполняйте жим с паузой или поочередно каждой рукой.',
                                                                                                                                                                                  10, 4, '/exercises/incline-dumbbell-press.gif', 'gym', 1.5, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Пуловер с гантелью', 'upper_body',
                                                                                                                                                                                  'Пуловер с гантелью лёжа на скамье — упражнение для грудных мышц и широчайших спины, а также для расширения грудной клетки. Лягте поперёк скамьи так, чтобы верхняя часть спины и голова лежали на скамье, а таз свисал вниз (для большей амплитуды). Ноги согнуты в коленях, стопы на полу. Возьмите гантель за один диск обеими руками, руки вытянуты над грудью. Локти чуть согнуты (фиксированный угол). На вдохе медленно опустите гантель за голову по дуге, не меняя угол в локтях. Чувствуйте растяжение в грудных и широчайших. Остановитесь, когда гантель окажется на уровне головы или чуть ниже (насколько позволяет гибкость). На выдохе верните гантель в исходное положение, используя грудные мышцы и широчайшие (не трицепс). Главные ошибки: разгибание локтей (превращает в жим гантели), слишком низкое опускание (боль в плечах), отрыв таза от скамьи. Для облегчения используйте меньший вес. Для усложнения выполняйте пуловер с прямой скамьей и меньшей опорой.',
                                                                                                                                                                                  12, 4, '/exercises/dumbbell-pullover.gif', 'gym', 1.04, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Шраги с гантелями', 'upper_body',
                                                                                                                                                                                  'Шраги с гантелями — изолированное упражнение для трапециевидных мышц (верх спины). Встаньте прямо, в каждой руке по гантели, руки опущены вдоль туловища. Плечи расправлены, спина прямая, подбородок приподнят. На выдохе поднимите плечи вертикально вверх, как будто хотите дотянуться ими до ушей. Не сгибайте руки в локтях, не помогайте корпусом и не наклоняйтесь. В верхней точке задержитесь на 1–2 секунды, максимально сжимая трапеции. На вдохе медленно опустите плечи вниз до полного расслабления (плечи в исходном положении), но не круглите спину. Движение только в плечевых суставах. Главные ошибки: вращение плечами (круговые движения) — опасно для суставов, сгибание рук, наклон корпуса вперёд. Для облегчения используйте меньший вес. Для усложнения выполняйте шраги на одной ноге или с паузой внизу с контролируемым растяжением.',
                                                                                                                                                                                  15, 4, '/exercises/dumbbell-shrug.gif', 'gym', 0.63, 45);

-- Upper Body для среднего уровня (street) — техника без упоминания уровня
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Подтягивания средним хватом', 'upper_body',
                                                                                                                                                                                  'Классические подтягивания прямым хватом на ширине плеч — базовое упражнение для широчайших мышц спины, бицепса и мышц кора. Возьмитесь за перекладину хватом сверху на ширине плеч, повисните на прямых руках, плечи опущены и расслаблены. Сделайте вдох, затем на выдохе начните подтягиваться, сводя лопатки и ведя локти вниз и назад. Поднимайтесь до тех пор, пока подбородок не окажется выше перекладины. В верхней точке сделайте паузу на 1 секунду, дополнительно напрягая спину. На вдохе медленно опуститесь вниз до полного выпрямления рук, позволяя широчайшим растянуться. Не раскачивайтесь и не используйте инерцию. Темп: 2 секунды подъём, пауза, 3 секунды опускание. Главные ошибки: раскачка корпусом, подъём плеч к ушам, неполная амплитуда (подбородок не дотягивается), рывки. Для облегчения используйте резиновый эспандер или частичную амплитуду. Для усложнения добавьте вес на пояс или выполняйте подтягивания с паузой вверху.',
                                                                                                                                                                                  8, 4, '/exercises/pullup.gif', 'street', 2.5, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Подтягивания обратным хватом', 'upper_body',
                                                                                                                                                                                  'Подтягивания обратным хватом (ладони к себе) — акцент на бицепс и нижнюю часть широчайших. Возьмитесь за перекладину снизу, руки на ширине плеч или чуть уже. Повисните, плечи опущены. На выдохе подтянитесь, ведя локти вдоль корпуса. Старайтесь коснуться перекладины грудью (не подбородком). В верхней точке сделайте паузу, сильно сокращая бицепс и спину. На вдохе медленно опуститесь до полного выпрямления рук. Не раскачивайтесь. Дыхание: подъём — выдох, опускание — вдох. Главные ошибки: подъём плеч к ушам, неполная амплитуда, рывки. Для облегчения используйте эспандер. Для усложнения выполняйте подтягивания с отягощением или с паузой внизу.',
                                                                                                                                                                                  8, 4, '/exercises/chinup.gif', 'street', 2.38, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания на брусьях', 'upper_body',
                                                                                                                                                                                  'Отжимания на брусьях — базовое упражнение для нижней части груди, трицепсов и передних дельт. Встаньте на брусьях, выпрямите руки, корпус вертикально. Для акцента на грудь слегка наклоните корпус вперёд и сведите локти к корпусу не полностью. Для акцента на трицепс держите корпус вертикально, локти прижаты к рёбрам. На вдохе медленно согните руки, опускаясь, пока плечи не окажутся чуть ниже локтей (угол в локтях около 90 градусов). Не опускайтесь слишком низко, если чувствуете боль в плечах. На выдохе мощно выжмитесь вверх до почти прямых рук, не блокируя локти. Следите, чтобы плечи не «уходили» вперёд. Дыхание: вниз — вдох, вверх — выдох. Главные ошибки: раскачка, слишком широкий хват на брусьях, опускание ниже безопасного уровня, округление плеч вперёд. Для облегчения используйте гравитрон или резиновый эспандер. Для усложнения добавьте вес на пояс или выполняйте отжимания с паузой.',
                                                                                                                                                                                  10, 4, '/exercises/dips.gif', 'street', 1.85, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Подтягивания широким хватом', 'upper_body',
                                                                                                                                                                                  'Подтягивания широким хватом (руки значительно шире плеч) прорабатывают внешнюю часть широчайших мышц, делая спину визуально шире. Возьмитесь за перекладину хватом сверху на ширине около 1.5 плеча. Повисните, слегка прогнитесь в грудном отделе (лопатки сведены). На выдохе подтянитесь, стараясь коснуться перекладины верхней частью груди. Локти при этом разводятся в стороны. Амплитуда будет меньше, чем при среднем хвате. В верхней точке сделайте паузу на 1 секунду. На вдохе медленно опуститесь вниз до полного выпрямления рук. Не делайте рывков. Главные ошибки: подъём плеч к ушам, неполная амплитуда, раскачка. Для облегчения используйте эспандер. Для усложнения добавьте отягощение или выполняйте подтягивания с паузой в растянутой позиции.',
                                                                                                                                                                                  8, 4, '/exercises/wide-pullup.gif', 'street', 2.63, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Австралийские подтягивания', 'upper_body',
                                                                                                                                                                                  'Австралийские подтягивания на низкой перекладине — горизонтальные подтягивания, которые отлично развивают спину и бицепс, подготавливая к вертикальным подтягиваниям. Возьмитесь за низкую перекладину (на уровне пояса) прямым или обратным хватом на ширине плеч. Ноги вытяните вперёд, пятки упираются в пол. Тело прямое от пяток до макушки, пресс напряжён. Чем ниже перекладина и чем прямее тело, тем сложнее. На выдохе подтяните грудь к перекладине, сводя лопатки и сгибая руки. Локти идут вдоль корпуса (при обратном хвате) или разводятся (при прямом). В верхней точке задержитесь на секунду. На вдохе медленно опуститесь до полного выпрямления рук. Не провисайте в пояснице. Главные ошибки: прогиб в пояснице, подъём таза вверх, неполная амплитуда. Для облегчения поставьте ноги ближе к перекладине (тело более вертикально). Для усложнения положите ноги на возвышение (скамью) или используйте отягощение.',
                                                                                                                                                                                  12, 4, '/exercises/australian-pullup-advanced.gif', 'street', 1.17, 60);

-- Lower Body для среднего уровня (home) — техника без упоминания уровня
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Приседания с выпрыгиванием', 'lower_body',
                                                                                                                                                                                  'Приседания с выпрыгиванием (прыжковые приседания) — плиометрическое упражнение для взрывной силы ног и сердечно-сосудистой системы. Встаньте прямо, ноги на ширине плеч, руки перед собой или на поясе. Опуститесь в глубокий присед — бёдра параллельно полу или ниже, спина прямая, пятки не отрываются. Из нижней точки мощно выпрыгните вверх, полностью выпрямляя ноги. Взмахните руками для инерции. Приземляйтесь мягко на носки с перекатом на всю стопу, сразу же сгибая колени для амортизации и переходя в следующий присед. Не задерживайтесь в нижней точке. Дыхание: выдох на прыжке, вдох при приземлении. Главные ошибки: жёсткое приземление на прямые ноги, колени заваливаются внутрь, присед неглубокий, отрыв пяток до прыжка. Для облегчения выполняйте прыжки без приседа (просто подпрыгивания) или уменьшите амплитуду. Для усложнения добавьте вес (гантели) или увеличьте высоту прыжка.',
                                                                                                                                                                                  15, 4, '/exercises/jump-squat-advanced.gif', 'home', 1.07, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады с прыжком', 'lower_body',
                                                                                                                                                                                  'Выпады с прыжком (смена ног в прыжке) — динамическое упражнение для ягодиц, квадрицепсов и координации. Встаньте в положение выпада: правая нога впереди, левая сзади. Опуститесь так, чтобы оба колена были согнуты под прямым углом (90 градусов). Из этого положения мощно прыгните вверх, меняя ноги в воздухе: приземлитесь с левой ногой впереди, правой сзади. Сразу же опуститесь в выпад. Продолжайте без остановок. Корпус держите вертикально, пресс напряжён. Приземляйтесь мягко на носки с перекатом. Дыхание: выдох на прыжке, вдох при приземлении. Главные ошибки: переднее колено выходит за носок, корпус наклоняется вперёд, жёсткое приземление, потеря равновесия. Для облегчения делайте выпады без прыжка, но в быстром темпе. Для усложнения возьмите гантели в руки.',
                                                                                                                                                                                  12, 4, '/exercises/jumping-lunge.gif', 'home', 1.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Болгарские сплит-приседания', 'lower_body',
                                                                                                                                                                                  'Болгарские сплит-приседания — одностороннее упражнение с задней ногой на возвышении (стул, скамья). Отлично нагружает ягодицы и квадрицепс передней ноги, развивает баланс. Встаньте спиной к стулу на расстоянии шага. Поставьте подъём (или носок) правой ноги на стул. Левая нога впереди, стопа плотно на полу, колено над пяткой. Руки на поясе или с гантелями. На вдохе согните левую ногу, опуская таз вниз, пока левое бедро не станет параллельно полу. Правое колено при этом сгибается и почти касается пола (не ударяйте). Спина прямая, корпус не наклоняйте вперёд. На выдохе мощно выпрямите левую ногу, возвращаясь в исходное положение. Выполните все повторения на одну ногу, затем поменяйте. Главные ошибки: переднее колено выходит за носок, корпус заваливается вперёд, таз перекошен. Для облегчения уменьшите высоту опоры (низкий стул) или не опускайтесь так глубоко. Для усложнения возьмите гантели или увеличьте высоту опоры.',
                                                                                                                                                                                  10, 4, '/exercises/bulgarian-split-squat.gif', 'home', 1.9, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Приседания с паузой', 'lower_body',
                                                                                                                                                                                  'Приседания с паузой в нижней точке (можно с гантелью или без) удаляют инерцию и усиливают нагрузку на квадрицепсы и ягодицы. Встаньте прямо, ноги на ширине плеч, носки слегка развёрнуты. При необходимости возьмите гантель к груди (гоблет) или бутылки. На вдохе опуститесь в присед до параллели или ниже, сохраняя спину прямой и пятки на полу. Задержитесь в нижней точке на 2–3 секунды, сохраняя напряжение в ногах. Не «проваливайтесь» в суставах. На выдохе мощно выпрямитесь, не блокируя колени вверху. Темп медленный и контролируемый. Главные ошибки: округление спины, отрыв пяток, колени заваливаются внутрь, слишком короткая пауза. Для облегчения выполняйте приседания без паузы, но с контролем. Для усложнения увеличьте вес или время паузы.',
                                                                                                                                                                                  12, 4, '/exercises/pause-squat.gif', 'home', 1.21, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Зашагивания на стул с весом', 'lower_body',
                                                                                                                                                                                  'Зашагивания на стул (или скамью) с гантелями — функциональное упражнение для ягодиц, квадрицепсов и стабилизаторов. Встаньте перед устойчивым стулом (высота 30–50 см). В каждую руку возьмите по гантели (или бутылке). Поставьте правую ногу на стул полностью. На выдохе, отталкиваясь правой ногой, поднимитесь на стул, приставляя левую ногу. В верхней точке полностью выпрямитесь. На вдохе медленно опуститесь вниз, сначала правой ногой, затем левой. Не спрыгивайте. Выполните все повторения на одну ногу, затем поменяйте ведущую ногу. Главные ошибки: толчок ногой, стоящей на земле (должна работать нога на стуле), наклон корпуса вперёд, жёсткое опускание. Для облегчения используйте низкую скамью и без веса. Для усложнения увеличьте вес или высоту опоры.',
                                                                                                                                                                                  12, 4, '/exercises/step-up-weighted.gif', 'home', 1.38, 45);

-- Lower Body для среднего уровня (gym) — техника без упоминания уровня и объёмов
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Приседания со штангой', 'lower_body',
                                                                                                                                                                                  'Приседания со штангой на спине — базовое упражнение для развития квадрицепсов, ягодиц и мышц кора. Установите штангу на стойках на уровне чуть ниже плеч. Подойдите, положите гриф на трапециевидные мышцы (не на шею), сведите лопатки. Снимите штангу, сделайте шаг назад. Ноги на ширине плеч, носки слегка развёрнуты наружу. Спина прямая, пресс напряжён. На вдохе отведите таз назад и согните колени, опускаясь до параллели бёдер с полом или чуть ниже. Колени движутся в направлении носков, не заваливаются внутрь. Пятки не отрываются. В нижней точке сделайте паузу 0.5 секунды. На выдохе мощно выпрямитесь, не блокируя колени. Главные ошибки: округление спины, отрыв пяток, колени уходят вперёд за носки, таз «подворачивается». Для облегчения используйте меньший вес или приседайте неглубоко. Для усложнения выполняйте приседания с паузой или с резиной.',
                                                                                                                                                                                  10, 4, '/exercises/barbell-squat.gif', 'gym', 2.4, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Румынская тяга', 'lower_body',
                                                                                                                                                                                  'Румынская тяга со штангой (или гантелями) — упражнение для бицепса бедра, ягодиц и разгибателей спины. Встаньте прямо, ноги на ширине таза, штанга в опущенных руках хватом сверху. Слегка согните колени и зафиксируйте этот угол. Спина прямая, лопатки сведены. На вдохе, сохраняя прямую спину, наклоните корпус вперёд, отводя таз назад. Штанга скользит вдоль голеней и бёдер, не отрываясь. Наклоняйтесь до тех пор, пока не почувствуете сильное растяжение в задней поверхности бедра (обычно до середины голени). Не округляйте поясницу. На выдохе мощным усилием ягодиц и бицепса бедра вернитесь в исходное положение, выпрямляя корпус. Главные ошибки: округление спины, сгибание ног во время подъёма, отрыв штанги от ног. Для облегчения используйте меньший вес. Для усложнения выполняйте на одной ноге или с паузой в нижней точке.',
                                                                                                                                                                                  10, 4, '/exercises/romanian-deadlift.gif', 'gym', 2.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады со штангой', 'lower_body',
                                                                                                                                                                                  'Выпады вперёд со штангой на плечах — упражнение для ягодиц и квадрицепсов с акцентом на стабилизацию. Положите штангу на плечи (как для приседаний), встаньте прямо. Сделайте шаг вперёд правой ногой. На вдохе согните оба колена до 90 градусов: правое колено над пяткой, левое почти касается пола. Корпус вертикально, спина прямая. На выдохе оттолкнитесь правой ногой и вернитесь в исходное положение. Выполните все повторения на одну ногу, затем смените. Главные ошибки: переднее колено выходит за носок, наклон корпуса вперёд, касание задним коленом пола. Для облегчения делайте выпады без штанги или с гантелями. Для усложнения выполняйте выпады с шагом назад (меньше нагрузки на колени).',
                                                                                                                                                                                  8, 4, '/exercises/barbell-lunge.gif', 'gym', 2.75, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Гакк-приседания', 'lower_body',
                                                                                                                                                                                  'Гакк-приседания в тренажёре Гаккеншмидта — упражнение для акцента на квадрицепсы с минимальной нагрузкой на спину. Займите место в тренажёре, плечи под подушками, спина прижата к опоре. Ноги поставьте на платформу на ширине плеч, носки слегка развёрнуты. Руки держитесь за поручни. На вдохе медленно согните колени, опуская платформу, пока угол в коленях не достигнет 90 градусов (или чуть глубже). Пятки не отрывайте. На выдохе мощно выпрямите ноги, не блокируя колени. Главные ошибки: отрыв спины от опоры, сведение коленей внутрь, слишком глубокое опускание. Для облегчения используйте меньший вес. Для усложнения выполняйте с паузой в нижней точке или с частичной амплитудой.',
                                                                                                                                                                                  12, 4, '/exercises/hack-squat.gif', 'gym', 1.5, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Сгибание ног лежа с весом', 'lower_body',
                                                                                                                                                                                  'Сгибание ног лёжа в тренажёре — изолированное упражнение для бицепса бедра. Лягте на скамью тренажёра лицом вниз, колени чуть ниже края, валики находятся чуть выше пяток. Корпус плотно прилегает к скамье. На выдохе согните ноги, подтягивая валики к ягодицам, до угла в колене около 90 градусов. В верхней точке сделайте паузу на 1 секунду, максимально сжимая бицепс бедра. На вдохе медленно верните ноги в исходное положение, полностью выпрямляя колени, но не бросайте вес. Главные ошибки: отрыв таза от скамьи, слишком быстрый подъём, сгибание стоп наружу или внутрь (меняет акцент). Для облегчения уменьшите вес. Для усложнения выполняйте упражнение поочерёдно каждой ногой или с паузой в нижней точке.',
                                                                                                                                                                                  15, 4, '/exercises/leg-curl-weighted.gif', 'gym', 0.8, 60);

-- Lower Body для среднего уровня (street) — техника без упоминания уровня
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Приседания на одной ноге', 'lower_body',
                                                                                                                                                                                  'Приседания на одной ноге («пистолетик») с опорой — сложное упражнение для силы и баланса. Встаньте на одну ногу, вторую вытяните вперёд (можно держаться рукой за опору — столб, турник). Спина прямая, руки перед собой для баланса. На вдохе медленно приседайте на опорной ноге, отводя таз назад. Опускайтесь так глубоко, как позволяет гибкость (идеально — бедро параллельно полу или глубже). Вторая нога остаётся вытянутой вперёд, не касается пола. На выдохе мощно выпрямитесь, используя ягодицу и квадрицепс. Главные ошибки: округление спины, пятка опорной ноги отрывается, колено заваливается внутрь. Для облегчения используйте высокую опору или приседайте на стул. Для усложнения делайте без опоры или с весом в руках.',
                                                                                                                                                                                  8, 4, '/exercises/pistol-squat.gif', 'street', 2.88, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады с запрыгиванием на скамью', 'lower_body',
                                                                                                                                                                                  'Выпад и запрыгивание на скамью — комбинация для взрывной силы. Встаньте перед скамьёй (высота 30–40 см). Сделайте выпад правой ногой назад, опустив колено почти до пола. Из нижней точки выпада мощно выпрыгните, подтягивая правую ногу вперёд, и запрыгните на скамью на обе ноги. Спрыгните (или сойдите) назад и повторите с другой ноги. Корпус прямой, руки помогают. Приземляйтесь мягко. Главные ошибки: жёсткое приземление, неполный выпад, потеря равновесия. Для облегчения запрыгивайте на низкую скамью. Для усложнения увеличивайте высоту или вес.',
                                                                                                                                                                                  10, 4, '/exercises/lunge-to-box.gif', 'street', 2.1, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Спринтерские выпады', 'lower_body',
                                                                                                                                                                                  'Спринтерские выпады — быстрая смена ног в выпаде без прыжка, имитация бега. Встаньте в выпад (ноги на ширине таза, одна впереди, другая сзади). Напрягите пресс. Быстрым движением смените ноги: оттолкнитесь передней ногой и вынесите заднюю вперёд, одновременно отводя переднюю назад. Ноги не должны касаться пола одновременно — работа как поршни. Корпус вертикально, руки согнуты. Дышите ритмично. Главные ошибки: касание коленями пола, наклон корпуса вперёд, слишком большая амплитуда (делайте выпады неглубокими). Для облегчения замедлите темп. Для усложнения возьмите гантели.',
                                                                                                                                                                                  16, 4, '/exercises/split-squat-jump.gif', 'street', 1.06, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Зашагивания с прыжком на тумбу', 'lower_body',
                                                                                                                                                                                  'Зашагивание с прыжком на тумбу (box jump-step up) — плиометрическое упражнение. Встаньте перед тумбой (высота 30–60 см). Поставьте одну ногу на тумбу. Оттолкнитесь ею и выпрыгните вверх, приставляя вторую ногу. Приземлитесь на тумбу мягко на обе ноги. Сойдите или спрыгните. Затем повторите с другой ноги в качестве ведущей. Корпус прямой. Главные ошибки: жесткое приземление, запрыгивание с разбега (нужно с места), неполное выпрямление. Для облегчения используйте низкую тумбу. Для усложнения увеличивайте высоту или вес.',
                                                                                                                                                                                  10, 4, '/exercises/box-jump.gif', 'street', 2.2, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады в сторону с прыжком', 'lower_body',
                                                                                                                                                                                  'Боковые выпады с прыжком — для приводящих мышц и взрывной силы. Встаньте прямо, ноги шире плеч. Сделайте выпад в правую сторону: согните правую ногу, левая прямая. Из этого положения прыжком смените сторону, приземляясь в выпад влево. Руки помогают балансировать. Продолжайте без остановок. Спина прямая. Главные ошибки: колено выпадающей ноги выходит за носок, приземление на пятку. Для облегчения делайте выпады без прыжка. Для усложнения возьмите гантели.',
                                                                                                                                                                                  12, 4, '/exercises/side-lunge-jump.gif', 'street', 1.54, 45);

-- Full Body для среднего уровня (home) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Берпи с отжиманием', 'full_body',
                                                                                                                                                                                  'Берпи с отжиманием и прыжком — классическое полное берпи. Из положения стоя присядьте, поставьте ладони на пол. Прыжком уйдите в упор лёжа. Выполните одно отжимание (грудь касается пола). Прыжком подтяните ноги к рукам. Мощно выпрыгните вверх с хлопком над головой. Дыхание: отжимание — выдох, прыжок вверх — выдох. Приземляйтесь мягко. Главные ошибки: провисшая поясница в планке, неполное отжимание, приземление на прямые ноги. Для облегчения делайте без прыжка вверх или с отжиманием с колен. Для усложнения ускоряйте темп или добавляйте вес.',
                                                                                                                                                                                  12, 4, '/exercises/burpee.gif', 'home', 1.25, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Медвежья походка с отжиманием', 'full_body',
                                                                                                                                                                                  'Медвежья походка с отжиманием — комбинация передвижения на четвереньках и отжимания. Встаньте на четвереньки (ладони под плечами, колени под тазом). Выпрямите ноги, подняв колени на 5–10 см от пола (поза медведя). Сделайте несколько шагов вперёд (перекрёстно: правая рука — левая нога). Остановитесь, выполните отжимание. Продолжайте походку. Спина прямая, таз не поднимайте высоко. Главные ошибки: прогиб в пояснице, подъём таза, отжимание на коленях. Для облегчения делайте походку без отжиманий. Для усложнения ускоряйтесь.',
                                                                                                                                                                                  10, 4, '/exercises/bear-crawl-pushup.gif', 'home', 1.4, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Ситапы с весом', 'full_body',
                                                                                                                                                                                  'Ситапы с весом (блин, гантель за головой) — подъёмы корпуса с отягощением. Лягте на спину, согните колени, стопы на полу. Возьмите блин (или гантель) и держите двумя руками за головой (или на груди). На выдохе поднимите корпус, округляя спину, пока не коснётесь локтями коленей. На вдохе медленно опуститесь. Не отрывайте пятки. Главные ошибки: рывки головой, отрыв стоп, слишком быстрое опускание. Для облегчения используйте меньший вес или делайте без веса. Для усложнения выпрямите ноги.',
                                                                                                                                                                                  15, 4, '/exercises/weighted-situp.gif', 'home', 0.8, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Планка с переходом', 'full_body',
                                                                                                                                                                                  'Планка с переходом с рук на локти и обратно (коммандо). Примите планку на прямых руках. Поочерёдно согните левую руку, опускаясь на локоть, затем правую — вы в планке на локтях. Затем в обратном порядке вернитесь на прямые руки. Повторяйте. Тело прямое, таз не поднимается. Дыхание ровное. Главные ошибки: прогиб в пояснице, раскачка тазом. Для облегчения делайте переходы медленно. Для усложнения ускоряйтесь.',
                                                                                                                                                                                  16, 4, '/exercises/plank-walkout.gif', 'home', 0.66, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады с поворотом и весом', 'full_body',
                                                                                                                                                                                  'Выпады с поворотом корпуса с блином (или гантелью). Держите блин двумя руками у груди. Сделайте выпад вперёд правой ногой. В нижней точке выпада поверните корпус в правую сторону (блин двигается вместе). Вернитесь в центр. Оттолкнитесь и встаньте. Повторите на другую ногу. Корпус прямой, переднее колено над пяткой. Главные ошибки: поворот таза вместо плеч, наклон вперёд. Для облегчения делайте без поворота. Для усложнения увеличьте вес или амплитуду поворота.',
                                                                                                                                                                                  12, 4, '/exercises/lunge-twist-weight.gif', 'home', 1.17, 45);

-- Full Body для среднего уровня (gym) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Становая тяга', 'full_body',
                                                                                                                                                                                  'Классическая становая тяга — базовое упражнение для всех мышц задней цепи. Подойдите к штанге, стоящей на полу. Ноги на ширине таза, гриф над серединой стопы. Наклонитесь с прямой спиной, возьмите штангу хватом чуть шире плеч (разноимённый хват для тяжёлых весов). На выдохе мощно выпрямитесь, поднимая штангу вдоль голеней и бёдер. Спина прямая, плечи отведены назад. В верхней точке не прогибайтесь. На вдохе опустите штангу, отводя таз назад и сохраняя прямую спину. Главные ошибки: округление спины, рывок, подъём таза быстрее плеч. Для облегчения используйте меньший вес. Для усложнения выполняйте с паузой у пола.',
                                                                                                                                                                                  8, 4, '/exercises/deadlift.gif', 'gym', 3.5, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Приседания со штангой на груди', 'full_body',
                                                                                                                                                                                  'Фронтальные приседания со штангой на груди — акцент на квадрицепсы и мышцы кора. Положите штангу на передние дельты и ключицы, скрестив руки на грифе или держа хватом сверху. Локти высоко. Снимите штангу со стоек. Приседайте, держа спину прямой, опускаясь как можно глубже (пятки не отрывать). На выдохе поднимитесь. Главные ошибки: опускание локтей (штанга скатывается), округление спины. Для облегчения используйте меньший вес. Для усложнения выполняйте с паузой.',
                                                                                                                                                                                  8, 4, '/exercises/front-squat.gif', 'gym', 3.25, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Тяга верхнего блока к груди', 'full_body',
                                                                                                                                                                                  'Тяга верхнего блока к груди с акцентом на спину. Сядьте на тренажёр, зафиксируйте колени. Возьмитесь за рукоятку широким прямым хватом. Слегка отклоните корпус назад (20–30°). На выдохе тяните рукоятку к верхней части груди, сводя лопатки и опуская локти вниз-назад. Пауза внизу. На вдохе медленно верните. Главные ошибки: раскачка корпусом, тяга бицепсом, опускание за голову. Для облегчения уменьшите вес. Для усложнения используйте узкий обратный хват или паузу.',
                                                                                                                                                                                  12, 4, '/exercises/lat-pulldown-advanced.gif', 'gym', 1.17, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Жим гантелей стоя', 'full_body',
                                                                                                                                                                                  'Жим гантелей стоя с вовлечением ног (толчковый жим). Возьмите гантели к плечам. Слегка согните колени, затем мощно выпрямите их, помогая выжать гантели вверх над головой. Это толчок ногами добавляет инерцию. Опустите гантели под контролем. Упражнение развивает взрывную силу всего тела. Главные ошибки: сильный прогиб в спине, выталкивание только руками. Для облегчения делайте жим сидя. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  10, 4, '/exercises/standing-dumbbell-press.gif', 'gym', 1.6, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Тяга штанги к подбородку', 'full_body',
                                                                                                                                                                                  'Тяга штанги к подбородку (узким хватом) — упражнение для трапеций и дельт. Возьмите штангу узким хватом (ладони на расстоянии 10–20 см). Встаньте прямо. На выдохе, ведя локти вверх и в стороны, поднимите штангу к подбородку. Гриф скользит вдоль туловища. В верхней точке локти выше плеч. На вдохе опустите. Главные ошибки: слишком широкий хват (нагрузка на плечи), наклон корпуса вперёд. Для облегчения используйте гантели. Для усложнения выполняйте медленно.',
                                                                                                                                                                                  12, 4, '/exercises/upright-row.gif', 'gym', 1.25, 60);

-- Full Body для среднего уровня (street) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Подтягивания с выходом', 'full_body',
                                                                                                                                                                                  'Подтягивания с частичным выходом на одну руку. Подтянитесь до уровня подбородка, затем сместите корпус в сторону, выводя одно плечо выше перекладины. Задержитесь, затем вернитесь. Требует силы и координации. Дыхание: подъём — выдох. Главные ошибки: раскачка, недостаточная амплитуда. Для облегчения делайте с помощью резины. Для усложнения делайте полный выход на две руки.',
                                                                                                                                                                                  6, 4, '/exercises/pullup-partial.gif', 'street', 4.0, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Берпи с подтягиванием', 'full_body',
                                                                                                                                                                                  'Берпи с подтягиванием на турнике. Выполните берпи (с отжиманием и прыжком) под турником. После прыжка вверх схватитесь за перекладину и выполните одно подтягивание. Спрыгните и повторите. Требует выносливости. Главные ошибки: слабое берпи, неполное подтягивание. Для облегчения делайте без отжимания или с подтягиванием обратным хватом.',
                                                                                                                                                                                  8, 4, '/exercises/burpee-pullup.gif', 'street', 3.25, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Отжимания на брусьях с подъемом ног', 'full_body',
                                                                                                                                                                                  'Отжимания на брусьях с подъёмом прямых ног вперёд. Встаньте на брусья, выпрямите руки. На выдохе выполните отжимание на брусьях. В верхней точке, не опускаясь, поднимите прямые ноги вперёд до параллели с полом (угол 90° в тазу). Опустите ноги. Повторите. Развивает грудь, трицепс и пресс. Главные ошибки: раскачка, сгибание ног в коленях. Для облегчения поднимайте согнутые ноги. Для усложнения добавляйте вес.',
                                                                                                                                                                                  10, 4, '/exercises/dips-leg-raise.gif', 'street', 2.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Зашагивания с жимом над головой', 'full_body',
                                                                                                                                                                                  'Зашагивания на скамью с жимом гантели (или камня) над головой. В руках гантель (или бутылка). Зашагните правой ногой на скамью, поднимитесь и одновременно выжмите гантель вверх. Опуститесь, верните гантель к плечу. Чередуйте ноги. Развивает ноги, плечи, координацию. Главные ошибки: наклон корпуса, жим до выпрямления ног. Для облегчения делайте без жима. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  12, 4, '/exercises/step-up-press.gif', 'street', 1.42, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады с подтягиванием', 'full_body',
                                                                                                                                                                                  'Выпад с имитацией подтягивания (или с эспандером). Выполните выпад назад. В нижней точке сделайте тяговое движение руками (имитация подтягивания) — используйте эспандер, закреплённый вверху, или просто движение. Развивает спину и ноги одновременно. Главные ошибки: потеря равновесия, неполная амплитуда. Для облегчения делайте без эспандера. Для усложнения увеличьте сопротивление.',
                                                                                                                                                                                  12, 4, '/exercises/lunge-pullup-mime.gif', 'street', 1.33, 45);

-- Cardio для среднего уровня (home) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Берпи с прыжком', 'cardio',
                                                                                                                                                                                  'Классическое берпи с высоким прыжком. Из положения стоя присядьте, поставьте руки на пол. Прыжком уйдите в упор лёжа. Выполните отжимание (грудь касается пола). Прыжком подтяните ноги к рукам. Мощно выпрыгните вверх как можно выше, хлопнув над головой. Приземляйтесь мягко. Дышите ритмично. Главные ошибки: провисание поясницы в планке, приземление на пятки. Для облегчения делайте без отжимания. Для усложнения добавляйте вес или ускоряйтесь.',
                                                                                                                                                                                  15, 4, '/exercises/burpee-jump.gif', 'home', 12.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Скалолаз в быстром темпе', 'cardio',
                                                                                                                                                                                  'Скалолаз в быстром темпе — поочерёдное подтягивание коленей к груди в упоре лёжа. Примите планку на прямых руках. Быстро, как спринтер, поочерёдно подтягивайте колени к груди. Стопы отрываются от пола только на шаг. Темп максимальный, но сохраняйте корпус неподвижным. Дыхание частое. Главные ошибки: подъём таза, прогиб в пояснице. Для облегчения замедлите темп. Для усложнения делайте с отягощением на ногах.',
                                                                                                                                                                                  40, 4, '/exercises/mountain-climber-fast.gif', 'home', 11.5, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Джампинг Джекс', 'cardio',
                                                                                                                                                                                  'Джампинг Джекс (прыжки ноги вместе-врозь) в быстром темпе. Встаньте прямо, ноги вместе, руки вдоль тела. Прыжком расставьте ноги на ширину плеч и одновременно поднимите руки вверх через стороны до хлопка. Прыжком вернитесь. Сохраняйте мягкое приземление на носки. Дышите ритмично. Главные ошибки: жёсткое приземление, неполное разведение рук. Для облегчения делайте шагом. Для усложнения добавьте поворот корпуса.',
                                                                                                                                                                                  40, 4, '/exercises/jumping-jacks-fast.gif', 'home', 9.5, 15),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Бёрпи с отжиманием', 'cardio',
                                                                                                                                                                                  'Полное бёрпи с отжиманием от пола и прыжком вверх. Подробное описание: см. выше (берпи с отжиманием). В кардио-версии темп максимальный, отдых минимальный. Главное — непрерывность. Главные ошибки: остановки, неполная амплитуда. Для облегчения делайте без прыжка вверх. Для усложнения делайте двойное отжимание.',
                                                                                                                                                                                  12, 4, '/exercises/burpee.gif', 'home', 13.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Бег с захлестом голени', 'cardio',
                                                                                                                                                                                  'Бег на месте с захлёстом голени — пятки касаются ягодиц. Встаньте прямо. Бегите на месте, aggressively сгибая ноги в коленях так, чтобы пятки ударяли по ягодицам. Корпус слегка наклонён вперёд. Руки работают. Дыхание частое. Главные ошибки: наклон корпуса назад, недостаточный захлёст. Для облегчения делайте без касания. Для усложнения ускоряйтесь.',
                                                                                                                                                                                  50, 4, '/exercises/butt-kicks-fast.gif', 'home', 10.0, 15);

-- Cardio для среднего уровня (gym) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Интервальный бег на дорожке', 'cardio',
                                                                                                                                                                                  'Чередование быстрого бега и медленного бега или ходьбы. Настройте дорожку. После разминки увеличьте скорость до быстрого бега (80–90% от максимума) на 30–60 секунд. Затем снизьте скорость до спокойного бега или ходьбы на 60–90 секунд для восстановления. Повторяйте циклы. Следите за пульсом. Главные ошибки: отсутствие восстановления, слишком длинные интервалы. Для облегчения делайте ходьба/бег. Для усложнения увеличьте наклон или длительность спринтов.',
                                                                                                                                                                                  45, 4, '/exercises/treadmill-interval.gif', 'gym', 12.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Сайклинг', 'cardio',
                                                                                                                                                                                  'Интенсивная езда на велотренажёре. Установите сопротивление, при котором можете поддерживать быстрый темп (80–100 об/мин) с трудом. Крутите педали стоя или сидя, чередуя интервалы высокой интенсивности (30–60 секунд) и низкой (60 секунд). Держите спину прямо, не опирайтесь на руль всем телом. Главные ошибки: слишком низкое сиденье, остановка педалей. Для облегчения уменьшите сопротивление. Для усложнения добавьте спринты по 10–15 секунд.',
                                                                                                                                                                                  45, 4, '/exercises/cycling-intensive.gif', 'gym', 13.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Гребля', 'cardio',
                                                                                                                                                                                  'Гребля на тренажёре в интенсивном темпе. Следуйте фазе: захват — проводка ногами — наклон корпуса — тяга руками; возврат в обратном порядке. Гребите мощно, с частотой 25–30 гребков в минуту. Делайте интервалы: 1 минута максимум, 1 минута легко. Спина прямая, не горбитесь. Главные ошибки: сгибание спины вперёд, использование только рук. Для облегчения снизьте сопротивление. Для усложнения увеличьте длительность интервалов.',
                                                                                                                                                                                  45, 4, '/exercises/rowing-intensive.gif', 'gym', 14.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Берпи на месте', 'cardio',
                                                                                                                                                                                  'Берпи в зале (классика). Выполняйте полное берпи с отжиманием от пола и прыжком вверх. Старайтесь делать без пауз, целыми сериями. Контролируйте дыхание. Главные ошибки: расплывчатая техника из-за усталости. Для облегчения делайте без отжимания. Для усложнения делайте двойное отжимание или запрыгивание на степ-платформу.',
                                                                                                                                                                                  20, 4, '/exercises/burpee-gym.gif', 'gym', 15.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Скакалка', 'cardio',
                                                                                                                                                                                  'Прыжки на скакалке в быстром темпе. Вращайте скакалку кистями, прыгайте невысоко (1–2 см). Дышите ритмично. Можно выполнять интервалами: 30 секунд максимально, 15 секунд отдых. Главные ошибки: высокие прыжки, вращение плечами. Для облегчения прыгайте без скакалки. Для усложнения делайте двойные прыжки (два оборота за прыжок).',
                                                                                                                                                                                  100, 4, '/exercises/jump-rope-fast.gif', 'gym', 14.5, 20);

-- Cardio для среднего уровня (street) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Интервальный бег', 'cardio',
                                                                                                                                                                                  'Чередование спринта (максимальная скорость) и трусцы (восстановление) на улице. Выберите ровную дорожку (100–200 м). Спринтуйте 30 секунд, затем бегите трусцой 60 секунд. Повторяйте. Следите за пульсом. Главные ошибки: недостаточное восстановление, плохая техника спринта (заваливание корпуса). Для облегчения уменьшите спринт до 20 секунд. Для усложнения увеличьте спринт до 60 секунд.',
                                                                                                                                                                                  45, 4, '/exercises/interval-running.gif', 'street', 14.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Бег по лестнице', 'cardio',
                                                                                                                                                                                  'Бег вверх по лестнице. Найдите длинную лестницу (стадион, парк). Бегите вверх, высоко поднимая колени, активно работая руками. Наверх — бегом, вниз — шагом (восстановление). Повторяйте. Дышите ритмично. Главные ошибки: перескакивание через ступеньки (травмоопасно), опора на перила. Для облегчения идите быстрым шагом. Для усложнения бегите вверх с небольшим весом (рюкзак).',
                                                                                                                                                                                  45, 4, '/exercises/stairs-running.gif', 'street', 16.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Скакалка на улице', 'cardio',
                                                                                                                                                                                  'Прыжки на скакалке в быстром темпе на свежем воздухе. Скакалка должна быть по длине. Прыгайте на носках, колени мягкие, корпус прямой. Выполняйте серии по 60–120 секунд максимум. Отдых по пульсу. Главные ошибки: удары скакалкой по ногам, запутывание. Для облегчения прыгайте без скакалки. Для усложнения делайте двойные прыжки или прыжки на одной ноге.',
                                                                                                                                                                                  150, 4, '/exercises/jump-rope-outdoor.gif', 'street', 15.0, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Фартлек', 'cardio',
                                                                                                                                                                                  'Игровой бег с переменной скоростью. Бегите по пересечённой местности, произвольно ускоряясь на отрезках (до дерева, до скамейки) и замедляясь. Нет строгих интервалов. Развивает выносливость и получается естественно. Главное — не останавливаться и чередовать усилия. Для облегчения делайте быструю ходьбу вместо спринтов. Для усложнения увеличивайте длину ускорений.',
                                                                                                                                                                                  60, 4, '/exercises/fartlek.gif', 'street', 14.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Бёрпи на улице', 'cardio',
                                                                                                                                                                                  'Берпи на открытом воздухе (на траве или резиновом покрытии). Полное берпи с отжиманием и прыжком. Выполняйте сериями по 10–20 повторений. Темп максимальный, но сохраняйте технику. Главные ошибки: отжимание на жёсткой поверхности (берегите запястья). Для облегчения делайте на коленях. Для усложнения делайте двойное отжимание или запрыгивание на возвышенность.',
                                                                                                                                                                                  20, 4, '/exercises/burpee-street.gif', 'street', 15.5, 30);

-- Flexibility для среднего уровня (home) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Продольный шпагат', 'flexibility',
                                                                                                                                                                                  'Растяжка на продольный шпагат (правый и левый). Встаньте на колено правой ноги, левая нога впереди, стопа на полу. Отводите таз вперёд, выпрямляя переднюю ногу и опуская таз к полу. Дышите глубоко, на выдохе расслабляйтесь и опускайтесь ниже. Удерживайте положение 30–60 секунд. Затем смените ногу. Не делайте через боль. Главные ошибки: перекос таза, округление спины. Для облегчения подложите подушку под таз. Для усложнения делайте на скользком полу.',
                                                                                                                                                                                  6, 4, '/exercises/front-split.gif', 'home', 4.0, 40),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Поперечный шпагат', 'flexibility',
                                                                                                                                                                                  'Растяжка на поперечный шпагат. Сядьте на пол, ноги широко в стороны, спина прямая. Медленно наклоняйтесь вперёд, вытягивая руки перед собой. Не округляйте спину. На выдохе углубляйте наклон. Стопы тяните на себя. Удерживайте 30–60 секунд. Главные ошибки: округление спины, сгибание коленей. Для облегчения сядьте на подушку. Для усложнения используйте утяжелители на ноги.',
                                                                                                                                                                                  6, 4, '/exercises/side-split.gif', 'home', 4.5, 40),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Мостик', 'flexibility',
                                                                                                                                                                                  'Гимнастический мостик из положения лёжа. Лягте на спину, ноги согните в коленях, стопы на полу. Ладони положите за головой пальцами к плечам. На выдохе оттолкнитесь руками и ногами, поднимая таз и корпус вверх, образуя дугу. Голова нейтрально или опущена. Удерживайте 10–30 секунд. Медленно опуститесь. Главные ошибки: опора на голову, недостаточный прогиб в грудном отделе. Для облегчения делайте мостик с опорой на стул. Для усложнения выполняйте из положения стоя.',
                                                                                                                                                                                  6, 4, '/exercises/bridge.gif', 'home', 5.0, 40),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Бабочка с наклоном', 'flexibility',
                                                                                                                                                                                  'Бабочка — сидя, стопы вместе, колени разведены. Сядьте, соедините стопы, притяните пятки к промежности. Руками возьмитесь за стопы. На выдохе наклонитесь вперёд, стараясь коснуться лбом пола (или грудью стоп). Спина прямая, колени старайтесь прижать к полу. Удерживайте 30–60 секунд. Главные ошибки: округление спины, подпрыгивания. Для облегчения сядьте выше на подушку. Для усложнения наклоняйтесь с выпрямленными ногами.',
                                                                                                                                                                                  10, 4, '/exercises/butterfly-stretch.gif', 'home', 3.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Складка сидя', 'flexibility',
                                                                                                                                                                                  'Глубокая складка сидя — наклон к прямым ногам с захватом стоп. Сядьте, ноги вместе, прямые, стопы на себя. На вдохе вытяните позвоночник, на выдохе наклонитесь вперёд от тазобедренных суставов, захватывая руками стопы. Притягивайте грудь к ногам, не округляя спину. Удерживайте 30–60 секунд. Главные ошибки: сгибание коленей, округление спины. Для облегчения используйте ремешок. Для усложнения делайте на одной ноге.',
                                                                                                                                                                                  8, 4, '/exercises/seated-fold.gif', 'home', 3.8, 30);

-- Flexibility для среднего уровня (gym) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка на шведской стенке', 'flexibility',
                                                                                                                                                                                  'Растяжка ног у шведской стенки. Встаньте лицом к стенке, поднимите ногу на перекладину на комфортной высоте. На выдохе наклонитесь к поднятой ноге, стараясь коснуться грудью колена. Спина прямая. Удерживайте 20–30 секунд. Смените ногу. Для глубокой растяжки — боком к стенке. Главные ошибки: разворот таза, сгибание опорной ноги. Для облегчения уменьшите высоту. Для усложнения поднимайте ногу выше.',
                                                                                                                                                                                  8, 4, '/exercises/wall-stretch.gif', 'gym', 4.5, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка с фитболом', 'flexibility',
                                                                                                                                                                                  'Растяжка спины и груди на фитболе. Лягте животом на мяч, раскатитесь так, чтобы мяч был под животом и тазом, ноги на полу. Расслабьте спину, свесив руки вниз. Чувствуйте растяжение в позвоночнике. Для грудных мышц: лягте спиной на мяч, разведите руки в стороны. Удерживайте 20–30 секунд. Главные ошибки: напряжение шеи. Для облегчения используйте меньший мяч. Для усложнения добавьте груз в руки.',
                                                                                                                                                                                  6, 4, '/exercises/ball-stretch-advanced.gif', 'gym', 5.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Вис с отягощением', 'flexibility',
                                                                                                                                                                                  'Вис на перекладине с небольшим грузом (например, утяжелитель на пояс) для пассивной растяжки позвоночника. Зафиксируйте вес (не более 5–10 кг). Повисните на прямых руках, полностью расслабьтесь. Удерживайте 20–40 секунд. Не раскачивайтесь. Главные ошибки: напряжение корпуса, отягощение слишком тяжёлое. Для облегчения вис без веса. Для усложнения увеличивайте вес постепенно.',
                                                                                                                                                                                  3, 4, '/exercises/hanging-weight.gif', 'gym', 5.5, 40),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка с эспандером', 'flexibility',
                                                                                                                                                                                  'Глубокая растяжка плеч и груди с эспандером. Заведите эспандер за спину одной рукой сверху, другой снизу, стараясь соединить кисти. Тяните, чувствуя растяжение в грудных мышцах и трицепсе. Удерживайте 20–30 секунд, затем смените руки. Также можно растягивать заднюю поверхность бедра, лёжа на спине и натягивая ленту на ногу. Главные ошибки: рывки, боль. Для облегчения держите ближе. Для усложнения уменьшите длину эспандера.',
                                                                                                                                                                                  10, 4, '/exercises/band-stretch-advanced.gif', 'gym', 4.2, 25),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Поза голубя', 'flexibility',
                                                                                                                                                                                  'Поза голубя для растяжки ягодиц и грушевидной мышцы. Из положения на четвереньках вытяните правую ногу вперёд, согнув её в колене так, чтобы правая голень лежала поперёк тела, перпендикулярно левому бедру. Левая нога вытянута назад. Опускайте таз к полу, держа корпус прямо. Удерживайте 30–60 секунд. Затем смените ногу. Главные ошибки: перенос веса на одну сторону, заваливание корпуса. Для облегчения подложите под ягодицу подушку. Для усложнения наклоняйтесь вперёд.',
                                                                                                                                                                                  8, 4, '/exercises/pigeon-pose.gif', 'gym', 4.0, 30);

-- Flexibility для среднего уровня (street) — техника
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка на турнике', 'flexibility',
                                                                                                                                                                                  'Вис на турнике с активной растяжкой. Повисните на прямых руках, затем раскачивайтесь из стороны в сторону лёгкими движениями таза, чтобы растянуть бока и спину. Можно делать круговые движения ногами. Удерживайте вис 30–60 секунд. Дышите ровно. Главные ошибки: резкие рывки, высокий хват. Для облегчения используйте низкую перекладину с частичной опорой ног.',
                                                                                                                                                                                  4, 4, '/exercises/bar-hang-stretch.gif', 'street', 4.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка у опоры', 'flexibility',
                                                                                                                                                                                  'Глубокая растяжка ног с опорой на скамью или столб. Поставьте одну ногу на опору (высота 50–100 см). На выдохе наклонитесь к поднятой ноге, стараясь коснуться стопы. Спина прямая. Удерживайте 30–40 секунд. Затем смените ногу. Вариант: боковая растяжка — повернитесь корпусом в сторону. Главные ошибки: округление спины, сгибание опорной ноги. Для облегчения уменьшите высоту. Для усложнения используйте самую высокую опору.',
                                                                                                                                                                                  8, 4, '/exercises/leg-stretch-deep.gif', 'street', 4.5, 25),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Наклоны к ногам стоя', 'flexibility',
                                                                                                                                                                                  'Глубокие наклоны вперёд стоя. Встаньте прямо, ноги на ширине плеч. На выдохе наклонитесь, расслабляя спину, и постарайтесь коснуться ладонями пола или обхватить голени. Колени не сгибайте. Удерживайте 20–30 секунд. Чтобы углубить, потянитесь к ногам. Главные ошибки: сгибание коленей, округление спины (позволительно при расслаблении, но не переусердствуйте). Для облегчения слегка согните колени. Для усложнения встаньте на возвышение.',
                                                                                                                                                                                  12, 4, '/exercises/standing-forward-bend-deep.gif', 'street', 4.2, 20),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Растяжка на брусьях', 'flexibility',
                                                                                                                                                                                  'Растяжка на брусьях для грудных мышц и трицепсов. Встаньте между брусьями, положите ладони на брусья (как для отжиманий) и медленно продавите грудную клетку вниз, создавая растяжение груди. Или повисните на брусьях, согнув ноги и расслабив плечи, для растяжки спины. Удерживайте 20–30 секунд. Главные ошибки: слишком глубокая амплитуда. Для облегчения делайте мягко. Для усложнения добавляйте вес.',
                                                                                                                                                                                  6, 4, '/exercises/bars-stretch.gif', 'street', 4.8, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'medium', 'Выпады с глубокой растяжкой', 'flexibility',
                                                                                                                                                                                  'Глубокие выпады для растяжки сгибателей бедра и паха. Сделайте очень широкий выпад (правой ногой вперёд), заднее колено на полу. Медленно подавайте таз вперёд, ощущая растяжение в левом паху и бедре. Руки можно поставить на правое колено. Удерживайте 30–40 секунд. Поменяйте ногу. Главные ошибки: наклон корпуса вперёд, отрыв задней стопы. Для облегчения держитесь за опору. Для усложнения поднимите заднее колено (бедро в воздухе).',
                                                                                                                                                                                  8, 4, '/exercises/lunge-deep-stretch.gif', 'street', 5.0, 30);
-- ==================== УПРАЖНЕНИЯ ДЛЯ ПРОДВИНУТЫХ (sportsman) ====================

-- ==================== УПРАЖНЕНИЯ ДЛЯ ПРОДВИНУТЫХ (sportsman) ====================

-- Upper Body для продвинутых (home) — полные описания
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Отжимания с хлопком', 'upper_body',
                                                                                                                                                                                  'Отжимания с хлопком — взрывное плиометрическое упражнение для развития мощности грудных мышц, трицепсов и передних дельт. Примите упор лёжа, руки чуть шире плеч, тело прямое, пресс и ягодицы напряжены. Медленно опуститесь в отжимание (как обычно), но в нижней точке накопите энергию. Взрывным движением вытолкните тело вверх так, чтобы руки оторвались от пола. В воздухе быстро хлопните в ладонями перед грудью. Приземлитесь мягко на слегка согнутые руки, сразу амортизируя локти, и переходите к следующему повторению. Дыхание: опускание — вдох, взрывной подъём — мощный выдох. Следите, чтобы поясница не прогибалась и таз не «проваливался» при приземлении. Главные ошибки: опаздывание с хлопком (руки успевают коснуться пола), жёсткое приземление на прямые локти, слабый толчок (недостаточная высота). Для облегчения делайте отжимания с отрывом рук, но без хлопка. Для усложнения выполняйте двойной хлопок или хлопок за спиной.',
                                                                                                                                                                                  15, 4, '/exercises/clap-pushup.gif', 'home', 1.67, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Отжимания в стойке на руках у стены', 'upper_body',
                                                                                                                                                                                  'Отжимания в стойке на руках у стены — упражнение для силы плеч, трицепсов и баланса. Встаньте на руки лицом к стене (ноги опираются на стену) или спиной (более сложно). Расставьте руки чуть шире плеч, пальцы направлены к стене или в стороны. Полностью выпрямите тело вертикально, ноги вместе, носки касаются стены. Пресс и ягодицы напряжены, поясница не прогибается. На вдохе медленно согните руки, опуская голову к полу (почти касаясь макушкой). Локти двигаются вперёд (в сторону стены) или чуть в стороны, но не разваливаются. Опускайтесь до тех пор, пока не почувствуете глубокое растяжение в плечах — обычно угол в локтях 90° или меньше. На выдохе мощно выжмитесь вверх, почти полностью выпрямляя руки, но не блокируя локти. Главные ошибки: сильный прогиб в пояснице («бананом»), разведение локтей перпендикулярно телу (нагрузка на плечевой сустав), неполная амплитуда. Для облегчения выполняйте у стены с подушкой под голову. Для усложнения делайте без стены (свободная стойка) или на брусьях.',
                                                                                                                                                                                  8, 4, '/exercises/handstand-pushup.gif', 'home', 4.38, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Индийские отжимания', 'upper_body',
                                                                                                                                                                                  'Индийские отжимания (дзюдо-отжимания) — динамическое упражнение для гибкости позвоночника, плеч и трицепсов. Встаньте в позу «собака мордой вниз»: таз высоко, ноги прямые, руки на полу на ширине плеч, голова между рук. На вдохе, сгибая руки, опустите голову и грудь к полу, прогибаясь в спине и одновременно опуская таз, чтобы корпус прошёл в «волне» — переходя в позу «кобра» (грудь вперёд, бёдра почти на полу). В конечной точке руки почти выпрямлены, взгляд вперёд. На выдохе обратным движением вернитесь в «собаку мордой вниз», выталкивая таз вверх и округляя спину. Дыхание синхронизировано с движением. Главные ошибки: отсутствие волны (прямой корпус), опора на живот при проходе. Для облегчения делайте более плавно. Для усложнения ускоряйте темп.',
                                                                                                                                                                                  15, 4, '/exercises/hindu-pushup.gif', 'home', 1.47, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Отжимания с поднятыми ногами', 'upper_body',
                                                                                                                                                                                  'Отжимания с ногами на возвышении (ноги выше головы) — акцент на верхнюю часть груди и передние дельты, а также увеличенный процент веса на руках. Поставьте ноги на высокую опору (стул, скамья, диван) так, чтобы угол наклона тела был 30–45°. Руки на полу чуть шире плеч, тело прямое, пресс напряжён. На вдохе медленно опуститесь грудью к полу, локти под 45°. На выдохе мощно выжмитесь вверх, почти выпрямляя руки. Следите, чтобы таз не провисал и не поднимался. Амплитуда полная (грудь касается пола или 1–2 см). Для увеличения сложности можно использовать рюкзак с грузом на спине. Главные ошибки: прогиб в пояснице, подъём таза выше плеч. Для облегчения уменьшите высоту опоры.',
                                                                                                                                                                                  15, 4, '/exercises/decline-pushup-advanced.gif', 'home', 1.73, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Планка с отжиманием', 'upper_body',
                                                                                                                                                                                  'Планка с отжиманием (переходы из планки на руках в планку на локтях и обратно с отжиманием). Начните в планке на прямых руках. На вдохе опуститесь на правое предплечье, затем на левое — вы в планке на локтях. На выдохе выполните отжимание от пола из планки на локтях (не поднимаясь) — просто напрягите грудные и трицепс, отрывая корпус на 2–3 см. Затем в обратном порядке вернитесь на прямые руки и повторите. Можно делать вариант без отжимания, только переходы. Главные ошибки: прогиб в пояснице, раскачка таза. Для облегчения делайте без отжимания. Для усложнения добавьте хлопок в переходе.',
                                                                                                                                                                                  12, 4, '/exercises/plank-pushup.gif', 'home', 2.0, 60);

-- Upper Body для продвинутых (gym) — полные описания
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Жим штанги лежа с весом', 'upper_body',
                                                                                                                                                                                  'Жим штанги лёжа с околопредельным весом — базовое упражнение для грудных, дельт и трицепсов с акцентом на силу. Лягте на скамью, сведите лопатки, прогните поясницу (естественно). Возьмите штангу хватом чуть шире плеч, сожмите гриф. Снимите штангу со стоек на выдохе, зафиксируйте над верхней частью груди. На вдохе медленно опустите гриф к нижней части груди (соски), локти под 45°. Коснитесь груди лёгким касанием (без отбива). На выдохе взрывным движением выжмите штангу вверх, немного назад. Сохраняйте напряжение во всём теле (ноги плотно на полу, таз прижат). Главные ошибки: отрыв таза от скамьи, слишком широкий хват, отбив грифа от груди, выключение локтей вверху. Для облегчения используйте меньший вес. Для усложнения выполняйте с паузой на груди 2–3 секунды.',
                                                                                                                                                                                  6, 4, '/exercises/heavy-bench-press.gif', 'gym', 5.33, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Тяга штанги в наклоне с весом', 'upper_body',
                                                                                                                                                                                  'Тяга штанги в наклоне к поясу с большим весом. Наклоните корпус почти до параллели с полом, спина прямая, колени согнуты. Хват чуть шире плеч, штанга висит на прямых руках. На выдохе мощной тягой мышц спины подтяните штангу к нижней части живота, сводя лопатки. Локти идут вдоль корпуса назад и вверх. В верхней точке пауза 0.5–1 секунда. На вдохе медленно опустите штангу, полностью выпрямляя руки, но не расслабляя спину. Главные ошибки: округление спины, рывок, подъём корпуса в момент тяги, использование бицепса вместо спины. Для облегчения уменьшите вес. Для усложнения выполняйте с паузой внизу.',
                                                                                                                                                                                  6, 4, '/exercises/heavy-bent-over-row.gif', 'gym', 5.0, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Жим Арнольда', 'upper_body',
                                                                                                                                                                                  'Жим Арнольда — жим гантелей сидя с поворотом кистей, прорабатывающий все пучки дельт. Сядьте на скамью с вертикальной спинкой, возьмите гантели перед собой на уровне подбородка ладонями к себе (супинированный хват). На выдохе начните выжимать гантели вверх, одновременно разворачивая кисти ладонями от себя. Полностью выпрямите руки над головой, ладони смотрят вперёд. На вдохе обратным движением вернитесь: опуская гантели, разворачивайте кисти ладонями к себе. Локти двигаются по дуге. Главные ошибки: слишком быстрый разворот, сгибание запястий. Для облегчения используйте меньший вес. Для усложнения делайте жим стоя.',
                                                                                                                                                                                  10, 4, '/exercises/arnold-press.gif', 'gym', 2.6, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Тяга Т-штанги', 'upper_body',
                                                                                                                                                                                  'Тяга Т-штанги в наклоне — упражнение для середины спины, широчайших и низов трапеций. Встаньте на платформу тренажёра, возьмитесь за рукояти нейтральным хватом (ладони друг к другу). Спина прямая, наклон корпуса 45°. На выдохе потяните рукояти к груди, сводя лопатки, локти идут назад и вверх. В верхней точке задержитесь на секунду. На вдохе медленно опустите вес, полностью выпрямляя руки. Главные ошибки: округление спины, использование инерции. Для облегчения уменьшите вес. Для усложнения делайте с паузой в растяжении.',
                                                                                                                                                                                  8, 4, '/exercises/t-bar-row.gif', 'gym', 3.5, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Жим Свенда', 'upper_body',
                                                                                                                                                                                  'Жим Свенда — изометрический жим с блином (диском) перед грудью. Возьмите один блин (5–15 кг) за края обеими руками, вытяните руки прямо перед собой на уровне груди. Сожмите блин с максимальным усилием, как будто хотите его раздавить. Сохраняя давление, выполняйте короткие жимовые движения вперёд-назад на 5–10 см (не сгибая локтей более 15°). Дышите ровно. Упражнение сильно нагружает грудные мышцы и трицепс статически. Главные ошибки: сгибание рук слишком сильно, ослабление хвата. Для облегчения используйте лёгкий блин. Для усложнения увеличивайте вес или делайте серии без перерыва.',
                                                                                                                                                                                  12, 4, '/exercises/svend-press.gif', 'gym', 1.67, 60);

-- Upper Body для продвинутых (street) — полные описания
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Подтягивания с весом', 'upper_body',
                                                                                                                                                                                  'Подтягивания с дополнительным весом (пояс с блином или рюкзак). Возьмитесь за перекладину средним прямым хватом. Зафиксируйте вес на поясе или наденьте рюкзак. Выполняйте подтягивания строго без раскачки: из полного виса подтянитесь до касания перекладины грудью, локти идут вниз-назад. В верхней точке пауза, затем медленное опускание с контролем (3 секунды). Дыхание: подъём — выдох, опускание — вдох. Главные ошибки: раскачка, неполная амплитуда (подбородок едва над перекладиной). Для облегчения используйте меньший вес. Для усложнения увеличивайте вес или делайте подтягивания обратным хватом.',
                                                                                                                                                                                  8, 4, '/exercises/weighted-pullup.gif', 'street', 4.38, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Выход силой', 'upper_body',
                                                                                                                                                                                  'Выход силой на турнике — гимнастический элемент для выхода на упор. Возьмитесь за перекладину хватом на ширине плеч. Подтянитесь высоко (грудь к перекладине), затем резко выкрутите локти вверх, переводя их над перекладиной, и выйдите в упор на прямые руки. Корпус вертикально. Обратным движением вернитесь в вис. Дыхание: подъём — мощный выдох. Главные ошибки: недостаточно высокое подтягивание, опоздание с выкрутом. Для облегчения используйте низкую перекладину или резину. Для усложнения делайте выход силой без маха.',
                                                                                                                                                                                  5, 4, '/exercises/muscle-up.gif', 'street', 9.0, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Отжимания на брусьях с весом', 'upper_body',
                                                                                                                                                                                  'Отжимания на брусьях с дополнительным весом (цепь, пояс, рюкзак). Встаньте на брусьях, выпрямите руки. Зафиксируйте вес. На вдохе медленно опуститесь, сгибая локти до угла 90° или глубже (исходя из гибкости плеч). Корпус можно слегка наклонить вперёд для акцента на грудь. На выдохе мощно выжмитесь вверх до почти прямых рук. Не раскачивайтесь. Главные ошибки: слишком глубокое опускание, вызывающее боль в плечах. Для облегчения используйте меньший вес. Для усложнения увеличивайте вес или делайте с паузой внизу.',
                                                                                                                                                                                  8, 4, '/exercises/weighted-dips.gif', 'street', 4.75, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Подтягивания широким хватом с весом', 'upper_body',
                                                                                                                                                                                  'Подтягивания широким хватом (руки шире плеч на 20–30 см) с отягощением. Хват сверху, вис. На выдохе подтянитесь, стараясь коснуться перекладины верхней частью груди. Локти разводятся в стороны. Амплитуда меньше, чем при среднем хвате, но нагрузка на широчайшие выше. Опускание подконтрольное. Главные ошибки: неполная амплитуда (подбородок не доходит), округление спины. Для облегчения уменьшите вес. Для усложнения увеличьте вес или делайте с паузой вверху.',
                                                                                                                                                                                  6, 4, '/exercises/weighted-wide-pullup.gif', 'street', 6.67, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Подтягивания с хлопком', 'upper_body',
                                                                                                                                                                                  'Взрывные подтягивания с хлопком за спиной (или перед собой). Возьмитесь за перекладину. Мощным усилием подтянитесь максимально высоко, чтобы в верхней точке можно было оторвать руки от перекладины и сделать хлопок. Приземлитесь обратно на перекладину. Для безопасности лучше выполнять на невысокой перекладине или с мягким покрытием. Главные ошибки: недостаточная высота подтягивания, потеря равновесия. Для облегчения сначала освойте подтягивания с отрывом без хлопка. Для усложнения делайте двойной хлопок.',
                                                                                                                                                                                  6, 4, '/exercises/clap-pullup.gif', 'street', 7.0, 120);
-- Lower Body для продвинутых (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания пистолетиком', 'lower_body',
                                                                                                                                                                                  'Приседания на одной ноге («пистолетик») без опоры — упражнение на силу, баланс и мобильность. Встаньте на одну ногу, вторую вытяните вперёд параллельно полу или чуть выше. Руки вытянуты вперёд для баланса. Медленно приседайте на опорной ноге, отводя таз назад и сохраняя спину прямой. Опускайтесь до тех пор, пока бедро опорной ноги не коснётся икры (или как можно глубже). Пятка не отрывается. Другая нога остаётся вытянутой вперёд, не касаясь пола. На выдохе мощно выпрямитесь. Главные ошибки: округление спины, пятка отрывается от пола, колено заваливается внутрь. Для облегчения используйте опору (стену) или неглубокое приседание. Для усложнения добавьте вес (гантель к груди).',
                                                                                                                                                                                  8, 4, '/exercises/pistol-squat-advanced.gif', 'home', 4.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Выпады с запрыгиванием на тумбу', 'lower_body',
                                                                                                                                                                                  'Выпад назад с последующим прыжком на возвышение (тумба, скамья). Встаньте перед тумбой. Сделайте выпад назад правой ногой, опустив левое колено почти до пола. Из нижней точки мощно выпрыгните вверх, меняя ноги в воздухе, и запрыгните на тумбу на обе ноги (или на левую). Сойдите назад и повторите. Дыхание: выдох на прыжке. Главные ошибки: недостаточно глубокий выпад, жёсткое приземление. Для облегчения запрыгивайте на низкую тумбу. Для усложнения увеличивайте высоту или вес.',
                                                                                                                                                                                  10, 4, '/exercises/lunge-to-box-advanced.gif', 'home', 3.4, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания с выпрыгиванием на тумбу', 'lower_body',
                                                                                                                                                                                  'Прыжки на тумбу из глубокого приседа. Встаньте перед тумбой (высота 40–70 см). Опуститесь в полный присед (бёдра параллельно полу или глубже). Из нижней точки взрывным движением выпрыгните вверх и запрыгните на тумбу, приземляясь обеими ногами. Мягко спрыгните (или сойдите) и повторите. Дыхание: выдох на прыжке. Главные ошибки: «залипание» в нижней точке, приземление на прямые ноги. Для облегчения используйте низкую тумбу. Для усложнения добавьте вес.',
                                                                                                                                                                                  8, 4, '/exercises/box-squat-jump.gif', 'home', 4.5, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с отжиманием и прыжком на тумбу', 'lower_body',
                                                                                                                                                                                  'Берпи полное (с отжиманием) + прыжок на тумбу. Выполните берпи: присед, упор лёжа, отжимание, подтягивание ног к рукам. Затем вместо обычного прыжка вверх — мощно прыгните на тумбу (высота 40–60 см). Спрыгните и сразу начните следующее берпи. Требует выносливости и взрывной силы. Дыхание: непрерывное. Главные ошибки: потеря темпа, приземление на тумбу согнувшись. Для облегчения используйте низкую тумбу или делайте без отжимания. Для усложнения увеличивайте высоту.',
                                                                                                                                                                                  8, 4, '/exercises/burpee-box-jump.gif', 'home', 4.75, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Зашагивания с прыжком и коленом', 'lower_body',
                                                                                                                                                                                  'Зашагивание на тумбу с прыжком и подъёмом колена (кик). Зашагните правой ногой на тумбу, затем мощно оттолкнитесь и выпрыгните вверх, подтягивая левое колено к груди. Приземлитесь на обе ноги на тумбу (или сойдите). Чередуйте ноги. Корпус прямой. Главные ошибки: потеря равновесия, недостаточный подъём колена. Для облегчения делайте без прыжка. Для усложнения добавьте вес в руки.',
                                                                                                                                                                                  10, 4, '/exercises/step-up-knee-advanced.gif', 'home', 3.2, 60);

-- Lower Body для продвинутых (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания со штангой с весом', 'lower_body',
                                                                                                                                                                                  'Тяжёлые приседания со штангой на спине (околопредельный вес). Техника классическая: штанга на трапеции, ноги на ширине плеч, носки развёрнуты. Глубокий присед (бедро ниже параллели) с контролем поясницы. На выдохе мощный подъём, без рывков. Используйте пояс и коленные бинты по необходимости. Главные ошибки: округление спины на выходе из приседа, подъём пяток. Для облегчения уменьшите вес. Для усложнения выполняйте с паузой в низу.',
                                                                                                                                                                                  5, 4, '/exercises/heavy-squat.gif', 'gym', 8.0, 180),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Становая тяга с весом', 'lower_body',
                                                                                                                                                                                  'Классическая становая тяга с околопредельным весом. Ноги на ширине таза, хват чуть шире плеч (разноимённый для тяжёлых весов). Спина идеально прямая. Подъём штанги за счёт ног, не спины. В верхней точке не прогибаться. Опускание контролируемое, с касанием пола без отбива. Главные ошибки: округление поясницы, рывок, отведение грифа от ног. Для облегчения используйте меньший вес. Для усложнения используйте эспандеры или выполняйте тягу с паузой у пола.',
                                                                                                                                                                                  5, 4, '/exercises/heavy-deadlift.gif', 'gym', 9.0, 180),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания над головой', 'lower_body',
                                                                                                                                                                                  'Оверхед-приседания (приседания со штангой над головой) — сложное упражнение на стабильность, гибкость плеч и спины. Возьмите штангу широким хватом и выжмите её над головой, зафиксировав в полном разгибании. Не сгибая рук, выполните приседание до параллели (или глубже), сохраняя штангу строго над центром стоп. Корпус прямой. Главные ошибки: потеря равновесия, сгибание рук, наклон штанги вперёд. Для облегчения используйте палку или гриф без веса. Для усложнения добавляйте вес.',
                                                                                                                                                                                  6, 4, '/exercises/overhead-squat.gif', 'gym', 6.33, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания в ножницы со штангой', 'lower_body',
                                                                                                                                                                                  'Разножка (сплит-приседания) со штангой на плечах (или на груди). Встаньте в выпад, штанга на плечах (как для приседаний). Опуститесь в сплит-приседание (переднее колено 90°, заднее почти касается пола). Задержитесь, затем вернитесь. Выполните все повторения на одну ногу, затем поменяйте. Дыхание: вниз — вдох, вверх — выдох. Главные ошибки: переднее колено выходит за носок, наклон корпуса вперёд. Для облегчения используйте меньший вес. Для усложнения выполняйте с паузой.',
                                                                                                                                                                                  8, 4, '/exercises/barbell-split-squat-advanced.gif', 'gym', 4.38, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Тяга сумо', 'lower_body',
                                                                                                                                                                                  'Становая тяга сумо (широкая постановка ног). Ноги широко, носки развёрнуты наружу, руки внутри коленей. Спина прямая. Тяга более вертикальная, с акцентом на приводящие мышцы и внутреннюю часть бедра. Опускайте штангу до касания пола. Главные ошибки: колени съезжают внутрь, округление спины. Для облегчения уменьшите вес. Для усложнения используйте паузу у пола.',
                                                                                                                                                                                  6, 4, '/exercises/sumo-deadlift.gif', 'gym', 7.0, 150);

-- Lower Body для продвинутых (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания с прыжком на высокую тумбу', 'lower_body',
                                                                                                                                                                                  'Прыжки на высокую коробку (60–100 см) из приседа. Встаньте перед тумбой. Опуститесь в полуприсед или полный присед. Взрывным движением выпрыгните и запрыгните на тумбу. Приземлитесь мягко, на носки. Слезьте и повторите. Главные ошибки: недостаточная высота, приземление на прямые колени. Для облегчения начните с низкой тумбы. Для усложнения увеличивайте высоту или держите вес.',
                                                                                                                                                                                  6, 4, '/exercises/box-jump-high.gif', 'street', 7.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Выпады с прыжком в высоту', 'lower_body',
                                                                                                                                                                                  'Выпады с прыжком вверх (динамические) с максимальной амплитудой. Выполните выпад с прыжком, стараясь в прыжке достать коленями груди (максимально высоко). Держите корпус вертикально. Приземляйтесь в выпад на противоположную ногу. Дыхание взрывное. Главные ошибки: потеря равновесия, недостаточный подъём. Для облегчения делайте без завышенного подъёма колен. Для усложнения добавьте вес.',
                                                                                                                                                                                  10, 4, '/exercises/jump-lunge-advanced.gif', 'street', 3.8, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Приседания на одной ноге с прыжком', 'lower_body',
                                                                                                                                                                                  '«Пистолетик» с прыжком — приседание на одной ноге с выпрыгиванием из нижней точки. Встаньте на одну ногу, вытяните вторую вперёд. Медленно присядьте до касания бедра икры, затем взрывным движением выпрыгните вверх, отрывая опорную ногу от земли. Приземлитесь на ту же ногу и сразу в следующий присед. Требует огромной силы и баланса. Главные ошибки: падение, приземление на пятку. Для облегчения используйте опору. Для усложнения делайте с весом.',
                                                                                                                                                                                  6, 4, '/exercises/single-leg-jump-squat-advanced.gif', 'street', 6.67, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с запрыгиванием на тумбу', 'lower_body',
                                                                                                                                                                                  'Полное берпи с отжиманием и прыжком на высокую тумбу (50 см+). Выполните берпи, затем мощно прыгните на тумбу. Спрыгните и повторите. Темп высокий. Главные ошибки: касание тумбы животом (недопрыг), расслабление корпуса. Для облегчения используйте низкую тумбу. Для усложнения делайте с двойным отжиманием.',
                                                                                                                                                                                  8, 4, '/exercises/burpee-box-jump-advanced.gif', 'street', 5.5, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Зашагивания с прыжком и сменой ноги', 'lower_body',
                                                                                                                                                                                  'Зашагивания на тумбу с прыжком и сменой ноги в воздухе (скачущие зашагивания). Зашагните правой ногой, оттолкнитесь и в прыжке поменяйте ноги так, чтобы приземлиться на левую ведущую. Затем повторите в ритме. Развивает координацию и взрывную силу. Главные ошибки: потеря ритма, падение. Для облегчения делайте без смены ноги. Для усложнения добавьте вес.',
                                                                                                                                                                                  10, 4, '/exercises/step-up-switch-advanced.gif', 'street', 3.6, 60);

-- Full Body для продвинутых (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с отжиманием и прыжком на тумбу', 'full_body',
                                                                                                                                                                                  'Полное берпи (с отжиманием) + запрыгивание на тумбу (высота 40–60 см). После отжимания, подтягивания ног к рукам, вместо прыжка на месте — прыжок на тумбу. Спрыгнуть и повторить. Сочетание выносливости, силы и координации. Главные ошибки: неполное отжимание, «залипание». Для облегчения используйте низкую тумбу. Для усложнения используйте высокую тумбу или добавьте вес.',
                                                                                                                                                                                  8, 4, '/exercises/burpee-box-jump-advanced.gif', 'home', 5.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с подтягиванием', 'full_body',
                                                                                                                                                                                  'Берпи + подтягивание на турнике (или перекладине). Выполните берпи (с отжиманием), затем из положения стоя подпрыгните, возьмитесь за перекладину и сделайте одно подтягивание. Спрыгните и повторите. Для дома — если есть настенный турник. Главные ошибки: слабое подтягивание из-за усталости. Для облегчения делайте подтягивания обратным хватом. Для усложнения — два подтягивания или с весом.',
                                                                                                                                                                                  6, 4, '/exercises/burpee-pullup-advanced.gif', 'home', 7.5, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Отжимания в стойке на руках', 'full_body',
                                                                                                                                                                                  'Отжимания в стойке на руках без опоры (свободная стойка). Встаньте на руки, балансируя. Медленно согните руки, опуская голову к полу, затем выжмитесь вверх. Требует исключительной силы плеч и баланса. Главные ошибки: падение, недостаточная глубина. Для облегчения делайте у стены. Для усложнения выполняйте на брусьях.',
                                                                                                                                                                                  5, 4, '/exercises/handstand-pushup-free.gif', 'home', 9.6, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с отжиманием и хлопком', 'full_body',
                                                                                                                                                                                  'Берпи с отжиманием и хлопком в прыжке. Полное берпи, затем мощный прыжок вверх с хлопком над головой или за спиной. Максимальная интенсивность. Главные ошибки: недопрыг, потеря ритма. Для облегчения делайте без хлопка. Для усложнения — двойной хлопок.',
                                                                                                                                                                                  10, 4, '/exercises/burpee-clap.gif', 'home', 3.8, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Комплексное упражнение', 'full_body',
                                                                                                                                                                                  'Сочетание приседа, отжимания и прыжка в одном повторении: присесть, отжаться (ноги остаются в приседе?), прыжок — варианты. Например: приседание → переход в упор лёжа → отжимание → подтягивание ног к рукам → выпрыгивание вверх. Кроссфит-стиль. Главное — непрерывность. Для облегчения уберите отжимание. Для усложнения добавьте вес.',
                                                                                                                                                                                  12, 4, '/exercises/complex.gif', 'home', 3.5, 60);

-- Full Body для продвинутых (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Кроссфит комплекс', 'full_body',
                                                                                                                                                                                  'Сочетание нескольких упражнений без отдыха (например, 5 раундов: 7 становых тяг, 7 берпи, 7 подтягиваний). Выполняется на время. Техника должна оставаться чистой при усталости. Главные ошибки: жертвование техникой ради скорости. Для облегчения уменьшите вес или количество. Для усложнения увеличьте раунды.',
                                                                                                                                                                                  5, 4, '/exercises/crossfit-complex.gif', 'gym', 10.0, 180),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Взятие штанги на грудь', 'full_body',
                                                                                                                                                                                  'Олимпийское взятие штанги на грудь (clean). С рывка или с пола: мощное разгибание ног и спины, подрыв, подсед, приём штанги на плечи (передние дельты) и вставание. Требует высокой техники, гибкости и взрывной силы. Главные ошибки: неполный подсед, удар штанги о ключицы. Для облегчения используйте гимнастическую палку. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  5, 4, '/exercises/clean.gif', 'gym', 9.6, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Толчок штанги', 'full_body',
                                                                                                                                                                                  'Толчок штанги от груди (jerk) — олимпийское движение. Из положения штанги на груди (чист) — полуприсед и взрывное выталкивание штанги вверх, с уходом в ножницы (или присед) и фиксацией над головой. Вставание. Главные ошибки: сгибание рук до фиксации, недостаточная глубина ножниц. Для облегчения используйте палку. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  5, 4, '/exercises/jerk.gif', 'gym', 9.8, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Рывок штанги', 'full_body',
                                                                                                                                                                                  'Олимпийский рывок (snatch) — штанга с пола над головой в одном непрерывном движении. Максимальная скорость и координация. Требует совершенной техники. Главные ошибки: несинхронное движение, потеря равновесия. Для облегчения используйте палку. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  4, 4, '/exercises/snatch.gif', 'gym', 13.0, 180),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Тяжелоатлетический комплекс', 'full_body',
                                                                                                                                                                                  'Комбинация рывковых и толчковых движений (например, рывок + толчок после взятия). Выполняется как одно повторение со сменой хвата. Техника сложная. Главные ошибки: перехват штанги в неподходящий момент. Для облегчения разбейте на отдельные движения. Для усложнения увеличивайте вес.',
                                                                                                                                                                                  4, 4, '/exercises/weightlifting-complex.gif', 'gym', 13.75, 180);

-- Full Body для продвинутых (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Воркаут комплекс', 'full_body',
                                                                                                                                                                                  'Круговая из подтягиваний, отжиманий на брусьях и приседаний (например, 10-20-30). Выполняется в максимальном темпе без отдыха между упражнениями. Главные ошибки: снижение техники к концу. Для облегчения уменьшите количество. Для усложнения добавьте вес.',
                                                                                                                                                                                  3, 4, '/exercises/workout-complex.gif', 'street', 14.67, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Выход силой с отжиманиями', 'full_body',
                                                                                                                                                                                  'Выход силой на турнике + отжимания на брусьях после выхода. Сделайте выход силой (выход в упор), затем спрыгните на брусья или сразу выполните несколько отжиманий на турнике (из упора). Требует большой силы. Главные ошибки: недостаточная высота выхода. Для облегчения используйте резину. Для усложнения добавьте вес.',
                                                                                                                                                                                  5, 4, '/exercises/muscle-up-dips.gif', 'street', 9.6, 150),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Подтягивания с отжиманиями на брусьях', 'full_body',
                                                                                                                                                                                  'Комбинация: подтягивания на турнике, затем переход на брусья и отжимания. Количество повторений одинаковое. Выполняется в связке без паузы. Главные ошибки: потеря хвата. Для облегчения делайте меньше повторений. Для усложнения добавьте вес.',
                                                                                                                                                                                  6, 4, '/exercises/pullup-dips-combo.gif', 'street', 7.67, 120),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с подтягиванием', 'full_body',
                                                                                                                                                                                  'Берпи (с отжиманием) + подтягивание. После прыжка вверх — хват за перекладину и одно подтягивание. Если турник низкий, можно сделать австралийское подтягивание. Повторять без остановки. Главные ошибки: усталость в хвате. Для облегчения делайте без отжимания. Для усложнения — два подтягивания.',
                                                                                                                                                                                  8, 4, '/exercises/burpee-pullup-advanced.gif', 'street', 5.88, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Силовой комплекс на турнике', 'full_body',
                                                                                                                                                                                  'Серия разных элементов на турнике: подтягивания, выход силой, подъём переворотом, отжимания в упоре. Выполняется как последовательность без отдыха. Главные ошибки: неправильный порядок, нехватка сил на последние элементы. Для облегчения уберите сложные элементы. Для усложнения добавьте вес.',
                                                                                                                                                                                  4, 4, '/exercises/bar-complex.gif', 'street', 12.25, 150);

-- Cardio для продвинутых (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с двойным отжиманием', 'cardio',
                                                                                                                                                                                  'Берпи, но с двумя отжиманиями подряд (сначала обычное, затем сразу второе, не поднимая рук). Затем прыжок вверх. Сильно увеличивает интенсивность. Дыхание: быстрое. Главные ошибки: неполные отжимания. Для облегчения делайте одно отжимание. Для усложнения — три отжимания.',
                                                                                                                                                                                  15, 4, '/exercises/double-burpee.gif', 'home', 18.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Скалолаз взрывной', 'cardio',
                                                                                                                                                                                  'Скалолаз в максимально быстром темпе (как спринт). Колени подтягивать к груди взрывно, частота шагов максимальная (более 3 в секунду). Сохранять правильную планку. Главные ошибки: подъём таза, потеря формы. Для облегчения снизьте темп. Для усложнения добавьте отягощение.',
                                                                                                                                                                                  60, 4, '/exercises/mountain-climber-explosive.gif', 'home', 16.0, 15),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Джампинг Джекс взрывные', 'cardio',
                                                                                                                                                                                  'Прыжки с максимальной амплитудой и скоростью. Ноги разводятся широко, руки поднимаются высоко над головой с хлопком. Приземление мягкое. Дыхание частое. Главные ошибки: жёсткое приземление. Для облегчения делайте без хлопка. Для усложнения добавьте двойной хлопок.',
                                                                                                                                                                                  50, 4, '/exercises/jumping-jacks-explosive.gif', 'home', 14.0, 15),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи с прыжком в высоту', 'cardio',
                                                                                                                                                                                  'Берпи с отжиманием, затем максимально высокий прыжок вверх, стараясь достать рукой до потолка. Акцент на взрывную силу. Главные ошибки: низкий прыжок. Для облегчения прыгайте невысоко. Для усложнения добейтесь запрыгивания на возвышение.',
                                                                                                                                                                                  15, 4, '/exercises/burpee-high-jump.gif', 'home', 19.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Интервальный комплекс', 'cardio',
                                                                                                                                                                                  'Чередование упражнений: 30 секунд берпи, 30 секунд скакалки, 30 секунд приседания с выпрыгиванием — без отдыха между раундами. Выполняется заданное количество раундов (3–5). Техника важна. Главные ошибки: снижение интенсивности. Для облегчения увеличьте отдых. Для усложнения сократите отдых.',
                                                                                                                                                                                  90, 4, '/exercises/interval-complex.gif', 'home', 20.0, 15);

-- Cardio для продвинутых (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Спринт на дорожке', 'cardio',
                                                                                                                                                                                  'Максимальный спринт на беговой дорожке в течение 10–20 секунд с последующим отдыхом. Установите высокую скорость (16+ км/ч). Бегите, высоко поднимая колени, мощно работая руками. После спринта — ходьба до восстановления пульса. Главные ошибки: держание за поручни, недостаточный наклон. Для облегчения снизьте скорость. Для усложнения увеличьте время спринта.',
                                                                                                                                                                                  15, 4, '/exercises/treadmill-sprint.gif', 'gym', 18.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Сайклинг спринт', 'cardio',
                                                                                                                                                                                  'Взрывная езда на велотренажёре с высоким сопротивлением. Крутите педали стоя максимально быстро 20–30 секунд, затем 60 секунд лёгкой езды. Повторяйте. Главные ошибки: остановка педалей, опора на руль. Для облегчения уменьшите сопротивление. Для усложнения увеличивайте длительность спринта.',
                                                                                                                                                                                  20, 4, '/exercises/bike-sprint.gif', 'gym', 17.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Гребля спринт', 'cardio',
                                                                                                                                                                                  'Взрывная гребля на тренажёре: 20 секунд максимальной мощности (частота гребков >35 в минуту), затем 40 секунд лёгкой гребли. Повторять. Техника — короткие, мощные гребки. Главные ошибки: плохая синхронизация, сгорбленная спина. Для облегчения снизьте сопротивление. Для усложнения увеличьте спринт до 30 секунд.',
                                                                                                                                                                                  20, 4, '/exercises/rowing-sprint.gif', 'gym', 19.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Эргометр', 'cardio',
                                                                                                                                                                                  'Работа на гребном эргометре с переменной интенсивностью: серия интервалов 1 минута на максимум / 1 минута лёгкая. Контролируйте дыхание. Главные ошибки: неполные гребки, перекос. Для облегчения уменьшите темп. Для усложнения используйте программу Tabata (20/10).',
                                                                                                                                                                                  60, 4, '/exercises/ergometer.gif', 'gym', 16.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Табата на велосипеде', 'cardio',
                                                                                                                                                                                  'Протокол Табата на велотренажёре: 20 секунд спринта с максимальной интенсивностью, 10 секунд отдыха — 8 циклов подряд. Держите высокий каденс. Главные ошибки: падение интенсивности к концу. Для облегчения снизьте сопротивление. Для усложнения добавьте вес или стойку педалирования.',
                                                                                                                                                                                  240, 4, '/exercises/tabata-bike.gif', 'gym', 20.0, 45);

-- Cardio для продвинутых (street)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Спринт в горку', 'cardio',
                                                                                                                                                                                  'Бег в гору максимально быстро (10–15 градусов, дистанция 50–100 м). Вверх — спринт, вниз — шагом (восстановление). Повторять. Мощная нагрузка на ноги и сердечно-сосудистую систему. Главные ошибки: слишком длинная дистанция, недостаточный наклон. Для облегчения бегите в гору не на максимуме. Для усложнения увеличьте длину или вес рюкзака.',
                                                                                                                                                                                  15, 4, '/exercises/hill-sprint.gif', 'street', 21.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Лестничный спринт', 'cardio',
                                                                                                                                                                                  'Бег вверх по лестнице максимально быстро. Чередовать: быстрый подъём (20–30 секунд), спуск шагом. Повторять. Главные ошибки: спотыкание, опора на перила. Для облегчения бегите не в полную силу. Для усложнения бегите через две ступеньки или с весом.',
                                                                                                                                                                                  25, 4, '/exercises/stairs-sprint.gif', 'street', 22.0, 90),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Скакалка двойные', 'cardio',
                                                                                                                                                                                  'Прыжки с двойным прокрутом скакалки (double-unders). За один прыжок скакалка проходит два раза под ногами. Высокая скорость вращения кистями, прыжок выше обычного. Дышите ритмично. Главные ошибки: запутывание скакалки, недостаточная высота прыжка. Для облегчения сначала освойте одинарные прыжки. Для усложнения делайте тройные.',
                                                                                                                                                                                  50, 4, '/exercises/double-unders.gif', 'street', 18.0, 30),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Фартлек сложный', 'cardio',
                                                                                                                                                                                  'Переменный бег по пересечённой местности с произвольными ускорениями и замедлениями, но с высоким общим темпом. Добавьте упражнения по ходу (отжимания, приседания). Главные ошибки: остановки. Для облегчения снизьте общий темп. Для усложнения увеличьте количество ускорений.',
                                                                                                                                                                                  60, 4, '/exercises/fartlek-advanced.gif', 'street', 20.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Берпи спринт', 'cardio',
                                                                                                                                                                                  'Берпи в максимальном темпе без остановки (например, 20 берпи на время). Старайтесь каждое берпи делать быстро, но с правильной техникой. Дыхание без задержек. Главные ошибки: «залипание» в нижней точке. Для облегчения делайте берпи без отжимания. Для усложнения добавьте отягощение.',
                                                                                                                                                                                  20, 4, '/exercises/burpee-sprint.gif', 'street', 21.0, 30);

-- Flexibility для продвинутых (home)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Шпагат продольный', 'flexibility',
                                                                                                                                                                                  'Полный продольный шпагат на правую и левую ногу. Из выпада постепенно выпрямляйте переднюю ногу, опуская таз к полу до полного касания. Дышите ровно, на выдохе расслабляйтесь. Удерживайте финальное положение 30–60 секунд. Главные ошибки: перекошенный таз, согнутые колени. Для облегчения используйте блоки (йога-кирпичи). Для усложнения делайте на наклонной поверхности.',
                                                                                                                                                                                  8, 4, '/exercises/front-split-full.gif', 'home', 5.5, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Шпагат поперечный', 'flexibility',
                                                                                                                                                                                  'Полный поперечный шпагат. Ноги широко в стороны, таз опускается до пола. Спина прямая. Можно постепенно наклоняться вперёд для углубления. Удерживайте 30–60 секунд. Главные ошибки: сгибание коленей, округление спины. Для облегчения сядьте на подушку. Для усложнения делайте у стены или с утяжелителями.',
                                                                                                                                                                                  8, 4, '/exercises/side-split-full.gif', 'home', 6.0, 60),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Мостик с подъемом', 'flexibility',
                                                                                                                                                                                  'Мостик (прогиб спины) + подъём одной ноги вверх. Из положения мостика (руки и стопы на полу) поднимите прямую ногу вверх, удерживая равновесие. Затем опустите и поднимите другую. Дыхание ровное. Главные ошибки: опора не на ладони, а на голову. Для облегчения делайте мостик без подъёма ноги. Для усложнения выполняйте из положения стоя.',
                                                                                                                                                                                  8, 4, '/exercises/bridge-leg-lift.gif', 'home', 6.5, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Складка с захватом', 'flexibility',
                                                                                                                                                                                  'Глубокая складка сидя (наклон к прямым ногам) с захватом стоп и удержанием. Сядьте, ноги вместе прямые. Наклонитесь, обхватите стопы руками и притяните корпус к ногам, сохраняя спину прямой (насколько возможно). Удерживайте 30–60 секунд. Главные ошибки: сгибание коленей, округление спины. Для облегчения используйте ремешок. Для усложнения делайте с вытянутыми руками за стопы.',
                                                                                                                                                                                  10, 4, '/exercises/seated-fold-hold.gif', 'home', 5.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Колечко', 'flexibility',
                                                                                                                                                                                  'Сложная растяжка спины и плеч: лёжа на животе, захватить руками стопы (как в луке), затем поднять бёдра и грудь, держа ноги согнутыми, образуя замкнутое «кольцо». Дышите ровно. Главные ошибки: недостаточный прогиб, отсутствие захвата. Для облегчения используйте ремень. Для усложнения увеличивайте время.',
                                                                                                                                                                                  6, 4, '/exercises/ring-stretch.gif', 'home', 6.0, 45);

-- Flexibility для продвинутых (gym)
INSERT INTO bodyfuel.exercise (id, level_preparation, name, type_exercise, description, base_count_reps, steps, link_gif, place_exercise, avg_calories_per, base_relax_time) VALUES
                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Растяжка на шведской стенке', 'flexibility',
                                                                                                                                                                                  'Глубокая растяжка ног у шведской стенки: подъём ноги на максимальную высоту (6–7 перекладина), наклон корпуса к ноге, удержание 30 секунд. Выполнять на обе ноги. Также боковая растяжка. Главные ошибки: сгибание опорной ноги. Для облегчения уменьшите высоту. Для усложнения используйте утяжелители.',
                                                                                                                                                                                  8, 4, '/exercises/wall-stretch-advanced.gif', 'gym', 6.0, 45),

                                                                                                                                                                                 (gen_random_uuid(), 'sportsman', 'Растяжка с партнером', 'flexibility',
